  // About /bank/about
  "about.backToBank": "Back to AEVION Bank",
  "about.headline": "Wallet for the trust graph",
  "about.lede": "AEVION Bank is the economic root of a creator-first ecosystem. Money composes with the things you make — royalties land automatically, credit grows with reputation, and every social moment can carry value.",
  "about.s1.kicker": "Composability",
  "about.s1.title": "Money where creative work happens",
  "about.s1.body": "QRight verifies your IP and pipes royalties into your wallet without a single click. CyberChess prize pools settle into your balance. Planet certificates compound into Trust Score. Bank isn't a separate app — it's the layer that makes everything else worth doing.",
  "about.s2.kicker": "Trust > collateral",
  "about.s2.title": "Credit gated by reputation, not paperwork",
  "about.s2.body": "Salary advances unlock as your Trust Score grows — earned across registrations, signed operations, repaid commitments and ecosystem activity. Trusted users get instant 500 AEC; Elite users 2000. No KYC theatre, no 'come back in three business days'.",
  "about.s3.kicker": "Social",
  "about.s3.title": "Every interaction can carry money",
  "about.s3.body": "Split a bill in three taps. Send a themed gift card with a personal message. Drop a payment request into a group circle. Schedule a recurring transfer that auto-pauses if your balance dips. The wallet meets people where conversations already happen.",
  "about.s4.kicker": "Sovereignty",
  "about.s4.title": "Your data, your device, your call",
  "about.s4.body": "Biometric guards on transfers above your threshold. QSign signs every operation with your Ed25519 key. Activity timeline flags anomalies before they hit your statement. Export the whole wallet as a portable JSON file — no lock-in, no hostage situation.",
  "about.cta.kicker": "Live MVP",
  "about.cta.title": "It works today.",
  "about.cta.body": "12 live modules. 18 wallet features. 11 sub-routes. Multilingual EN / RU / KZ. Installable as a PWA. The trust graph is real and growing.",
  "about.cta.openBank": "Open my wallet",
  "about.cta.exploreSurfaces": "Explore the bank",
  "about.cta.investorPitch": "Investor pitch",

  // Trust /bank/trust
  "trust.page.kicker": "AEVION · Trust Score",
  "trust.page.headline": "Reputation, computed.",
  "trust.page.lede": "Your Trust Score is a weighted blend of eight signals across banking and ecosystem. It gates how much credit you can pull instantly, and how much the wallet trusts your transfers. No paperwork, no opaque committee — the math is right here.",
  "trust.page.outOf100": "out of 100",
  "trust.page.currentTier": "Current tier",
  "trust.page.nextTier": "{points} pts to {tier} →",
  "trust.page.eliteAchieved": "★ Elite tier achieved — top of the ladder.",
  "trust.page.youAreHere": "You are here",
  "trust.page.points": "pts",
  "trust.page.ladder.kicker": "Ladder",
  "trust.page.ladder.title": "Four tiers, eight factors.",
  "trust.page.banking.kicker": "Banking signals",
  "trust.page.banking.title": "What you do in the wallet",
  "trust.page.ecosystem.kicker": "Ecosystem signals",
  "trust.page.ecosystem.title": "What you do across AEVION",
  "trust.page.wins.kicker": "Quick wins",
  "trust.page.wins.title": "The shortest path to your next tier",
  "trust.page.method.kicker": "Methodology",
  "trust.page.method.title": "How the score is computed",
  "trust.page.method.body": "Each factor scores 0-100 via a sub-linear curve — early progress moves the needle visibly, then saturates near a soft target. Factors are blended as a weighted mean (banking weights 0.8-1.2, ecosystem 0.7-1.2). A small +3 engagement bonus kicks in once any factor reaches 30 points, so brand-new users don't feel stuck. Tiers gate at 0 / 20 / 50 / 80. The whole calculation runs locally on your device — your wallet never leaves it.",
  "trust.page.cta.kicker": "Climb the ladder",
  "trust.page.cta.title": "Use the wallet, earn the trust.",
  "trust.page.cta.aboutLink": "Read the bank story",
  "trust.page.perks.new.1": "Wallet, P2P transfers, gift cards",
  "trust.page.perks.new.2": "Read-only access to the trust graph",
  "trust.page.perks.growing.1": "Salary advance up to 100 AEC",
  "trust.page.perks.growing.2": "Custom subscription scanner alerts",
  "trust.page.perks.trusted.1": "Salary advance up to 500 AEC instant",
  "trust.page.perks.trusted.2": "Public Trust Badge for embeds",
  "trust.page.perks.trusted.3": "Priority on shared payment requests",
  "trust.page.perks.elite.1": "Salary advance up to 2000 AEC instant",
  "trust.page.perks.elite.2": "Featured on Bank leaderboards",
  "trust.page.perks.elite.3": "Early access to new bank surfaces",

