  // Card /bank/card
  "card.kicker": "Wallet Card",
  "card.headline": "A card backed by your reputation.",
  "card.lede": "Your AEVION Bank card is a virtual artefact — a way to see your wallet identity at a glance and share it. The tier is your Trust Score; the foil shimmer marks it. No PVC, no plastic, no shipping fees.",
  "card.flipAria": "Flip card to see the back",
  "card.member": "Member",
  "card.memberSince": "Since",
  "card.back.title": "Verify on AEVION",
  "card.back.body1": "Scan the QR to open this wallet's public profile. The trust tier and score render server-side from the same audit log the bank uses internally.",
  "card.back.body2": "Card is non-transferable; tied to the device that holds the keypair.",
