  // Glossary /bank/glossary
  "glossaryPage.kicker": "Glossary",
  "glossaryPage.headline": "Every term, in one paragraph.",
  "glossaryPage.lede": "{count} terms across seven groups — currency, trust, saving, credit, privacy, social, ecosystem. Search to jump to any term, or scroll the groups.",
  "glossaryPage.searchPlaceholder": "Search terms and definitions…",
  "glossaryPage.searchAria": "Search glossary",
  "glossaryPage.searchEmpty": "Nothing matches “{q}”.",
  "glossaryPage.tocAria": "Glossary groups",
  "glossaryPage.readMore": "Read more",
  "glossaryPage.cta.kicker": "Cross-reference",
  "glossaryPage.cta.title": "Need more depth? Open the help page.",
  "glossaryPage.group.currency": "Currency & accounts",
  "glossaryPage.group.trust": "Trust system",
  "glossaryPage.group.saving": "Saving products",
  "glossaryPage.group.credit": "Credit",
  "glossaryPage.group.privacy": "Privacy & cryptography",
  "glossaryPage.group.social": "Social & payments",
  "glossaryPage.group.ecosystem": "AEVION ecosystem",
  "glossary.aec.term": "AEC",
  "glossary.aec.def": "Internal credit unit of the AEVION ecosystem. Pre-launch, 1 AEC ≈ $0.45 ≈ €0.42 ≈ 215 ₸. Treat as ecosystem credit, not a regulated currency.",
  "glossary.accountId.term": "Account-id",
  "glossary.accountId.def": "Opaque identifier of your wallet, format acc_<uuid>. Stable across sessions, used as the destination for transfers when you don't have someone's email.",
  "glossary.balance.term": "Balance",
  "glossary.balance.def": "Spendable AEC currently in your wallet — not counting pending Round-Up sweeps or locked Vault positions.",
  "glossary.topup.term": "Top-up",
  "glossary.topup.def": "Adding AEC to your wallet from an external source. Currently demo-only; production top-up rails ship with backend integration.",
  "glossary.displayCurrency.term": "Display currency",
  "glossary.displayCurrency.def": "Local currency you see amounts rendered in (USD / EUR / KZT / AEC). Conversion is display-only; the wallet stores AEC natively.",
  "glossary.trustScore.term": "Trust Score",
  "glossary.trustScore.def": "Reputation number 0–100 computed across 8 factors via weighted-mean math with a sub-linear curve. Gates how much credit you can pull instantly.",
  "glossary.trustTier.term": "Trust tier",
  "glossary.trustTier.def": "Discrete bucket your score lands in: New (0–19), Growing (20–49), Trusted (50–79), Elite (80+). Each tier unlocks visible perks.",
  "glossary.factor.term": "Trust factor",
  "glossary.factor.def": "Individual signal feeding the score: account age, banking volume, network breadth, activity, IP portfolio, IP reach, chess rating, planet bonuses.",
  "glossary.engagementBonus.term": "Engagement bonus",
  "glossary.engagementBonus.def": "+3 added to the score once any factor reaches 30. Stops brand-new users from feeling stuck on zero after first interactions.",
  "glossary.goal.term": "Goal",
  "glossary.goal.def": "Named savings bucket with an amount target and optional deadline (e.g. 'New laptop — 1500 AEC by Sept'). Doesn't lock funds; just tracks progress.",
  "glossary.vault.term": "AEC Vault",
  "glossary.vault.def": "Staking-style yield product. Lock AEC for 30 / 90 / 180 days in exchange for an APY multiplier scaled by your Trust tier. Early claim incurs a 50% gross penalty.",
  "glossary.roundUp.term": "Round-Up Stash",
  "glossary.roundUp.def": "Sweeps virtual change off every outgoing transfer (next multiple of 1 / 5 / 10 AEC) into a stash that can be claimed into a chosen Goal.",
  "glossary.apy.term": "APY",
  "glossary.apy.def": "Annual percentage yield on a Vault position — compounded across the lock-in term. Higher tiers and longer terms get bigger multipliers.",
  "glossary.earlyClaim.term": "Early claim",
  "glossary.earlyClaim.def": "Withdrawing a Vault position before maturity. The accrued yield is hit with a 50% gross penalty; net is what you actually receive.",
  "glossary.salaryAdvance.term": "Salary Advance",
  "glossary.salaryAdvance.def": "Instant AEC issued against future earnings. Limit gated by Trust tier (Trusted 500, Elite 2000). Repaid automatically from your next inflow with a small platform fee — no compound interest.",
  "glossary.creditLimit.term": "Credit limit",
  "glossary.creditLimit.def": "Maximum advance you can pull right now. A function of your Trust Score — climbs as the score climbs, falls back if signals weaken.",
  "glossary.qsign.term": "QSign",
  "glossary.qsign.def": "AEVION's Ed25519-based signing service. Every transfer is signed via /api/qsign/sign immediately after success; signatures live in the local audit log for re-verification.",
  "glossary.ed25519.term": "Ed25519",
  "glossary.ed25519.def": "Elliptic-curve digital-signature algorithm with strong security and small signature size. Backbone of QSign; the keypair lives on your device only.",
  "glossary.biometric.term": "Biometric guard",
  "glossary.biometric.def": "WebAuthn-backed fingerprint or face prompt that gates transfers above a configurable threshold. The biometric is local — only an unlock for the QSign keypair, never sent to a server.",
  "glossary.auditLog.term": "Audit log",
  "glossary.auditLog.def": "Local record of every signed operation. Persists in your browser; you can re-verify any historical entry against /api/qsign/verify and detect tampering.",
  "glossary.anomaly.term": "Anomaly",
  "glossary.anomaly.def": "Local flag raised on outgoing transfers that fall outside your normal pattern: unusually large amount, first-time recipient, burst of outgoing, late-night.",
  "glossary.export.term": "Export",
  "glossary.export.def": "JSON snapshot of 17 localStorage keys downloaded via Help → Export wallet. Re-import on any device to restore goals, signatures, gifts, contacts, and biometric thresholds.",
  "glossary.circle.term": "Circle",
  "glossary.circle.def": "Small shared group where members request and settle money against each other in a chat-like surface. Each circle has members + messages with embedded payment actions.",
  "glossary.split.term": "Split Bills",
  "glossary.split.def": "Tracker for a shared cost — total amount + a list of nicknames + amounts each owes. Tracks who paid; auto-archives once everyone settles.",
  "glossary.gift.term": "Gift",
  "glossary.gift.def": "Themed AEC transfer with a personal message and one of 10+ designs. Can be timelocked so the recipient only unlocks it on a specific date via /bank/gift/<id>.",
  "glossary.paymentRequest.term": "Payment request",
  "glossary.paymentRequest.def": "An invoice-like message sent to a contact or circle asking them to settle a specific amount. Recipient can accept, decline, or counter.",
  "glossary.recurring.term": "Recurring transfer",
  "glossary.recurring.def": "Scheduled outgoing transfer that fires on a cadence (weekly / monthly). Auto-pauses if your balance is below the planned amount and surfaces in the Inbox.",
  "glossary.contact.term": "Contact",
  "glossary.contact.def": "Saved recipient with a nickname mapped to their account-id. Powers autocomplete on /bank send forms; managed in the address book.",
  "glossary.qright.term": "QRight",
  "glossary.qright.def": "AEVION's IP/royalty module. Verifies original creative work and pipes royalty payouts directly into the wallet — feeds the IP-portfolio Trust factor.",
  "glossary.cyberchess.term": "CyberChess",
  "glossary.cyberchess.def": "AEVION's chess platform with prize-pool tournaments. Wins settle into the wallet; chess rating + podium count feed the chess Trust factor.",
  "glossary.planet.term": "Planet",
  "glossary.planet.def": "AEVION's stewardship layer where contributions earn certificates and bonuses. Planet payouts feed both the wallet and the planet Trust factor.",
  "glossary.qcoreai.term": "QCoreAI",
  "glossary.qcoreai.def": "AEVION's AI coordination layer. Routes prompts across agents and providers. Indirectly feeds the wallet via Multichat usage analytics.",
  "glossary.multichat.term": "Multichat Engine",
  "glossary.multichat.def": "Parallel multi-agent grid (6 roles, 5 LLM providers, persistent local sessions). Live module that uses AEVION accounts for billing and personalisation.",

