    "\u0412\u0430\u0448 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u043f\u0440\u0438\u0432\u044f\u0437\u0430\u043d \u043a AEVION-\u0438\u0434\u0435\u043d\u0442\u0438\u0444\u0438\u043a\u0430\u0442\u043e\u0440\u0443. \u0412\u043e\u0439\u0434\u0438\u0442\u0435 \u0438\u043b\u0438 \u0437\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044c \u2014 \u043c\u044b \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u0441\u043e\u0437\u0434\u0430\u0434\u0438\u043c AEC-\u043a\u043e\u0448\u0435\u043b\u0451\u043a \u0438 Trust Graph \u043f\u0440\u043e\u0444\u0438\u043b\u044c.",
  "auth.signIn.cta": "\u0412\u043e\u0439\u0442\u0438 / \u0417\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u2192",
