  "primer.eyebrow": "AEVION Bank \u00b7 \u041a\u043e\u043d\u0446\u0435\u043f\u0446\u0438\u044f",
  "primer.title.a": "\u0411\u0430\u043d\u043a, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0437\u0430\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u0442",
  "primer.title.b": "\u0432\u043c\u0435\u0441\u0442\u0435",
  "primer.title.c": "\u0441 \u0432\u0430\u043c\u0438 \u2014 \u0430 \u043d\u0435 \u043d\u0430 \u0432\u0430\u0441.",
  "primer.body":
    "AEVION Bank \u2014 \u0444\u0438\u043d\u0430\u043d\u0441\u043e\u0432\u044b\u0439 \u0441\u043b\u043e\u0439 \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u044b \u0438\u0437 27 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432. \u0412\u0430\u0448 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u0432\u0438\u0434\u0438\u0442 \u0440\u043e\u044f\u043b\u0442\u0438 \u043e\u0442 \u0432\u0430\u0448\u0435\u0433\u043e IP (QRight), \u043f\u0440\u0438\u0437\u043e\u0432\u044b\u0435 \u0438\u0437 \u0448\u0430\u0445\u043c\u0430\u0442 (CyberChess), \u0431\u043e\u043d\u0443\u0441\u044b Planet \u0438 P2P-\u043f\u0435\u0440\u0435\u0432\u043e\u0434\u044b \u2014 \u0432\u0441\u0451 \u044d\u0442\u043e \u0444\u043e\u0440\u043c\u0438\u0440\u0443\u0435\u0442 \u0435\u0434\u0438\u043d\u044b\u0439 Trust Score, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u0430\u0432\u0430\u043d\u0441\u044b, \u0442\u0438\u0440\u044b \u0438 \u043f\u0440\u0438\u0432\u0438\u043b\u0435\u0433\u0438\u0438. \u041f\u0440\u0438\u0432\u0430\u0442\u043d\u044b\u0439 AI Copilot \u0441\u043b\u0435\u0434\u0438\u0442 \u0437\u0430 \u044d\u0442\u0438\u043c \u0437\u0430 \u0432\u0430\u0441, \u0430 Autopilot \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u0438\u0442 \u043d\u0435\u0431\u043e\u043b\u044c\u0448\u0438\u0435 \u0441\u0443\u043c\u043c\u044b \u043a \u0432\u0430\u0448\u0438\u043c \u0446\u0435\u043b\u044f\u043c \u2014 \u043f\u043e \u0432\u0430\u0448\u0435\u043c\u0443 \u0441\u043e\u0433\u043b\u0430\u0441\u0438\u044e, \u0441 \u043b\u0438\u043c\u0438\u0442\u0430\u043c\u0438, \u043f\u043e\u0434 \u0430\u0443\u0434\u0438\u0442\u043e\u043c.",
  "primer.audience.user": "\u0415\u0441\u043b\u0438 \u0432\u044b \u0437\u0434\u0435\u0441\u044c, \u0447\u0442\u043e\u0431\u044b \u043a\u043e\u043f\u0438\u0442\u044c",
  "primer.audience.creator": "\u0415\u0441\u043b\u0438 \u0432\u044b \u0441\u043e\u0437\u0434\u0430\u0451\u0442\u0435",
  "primer.audience.investor": "\u0415\u0441\u043b\u0438 \u0432\u044b \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0435\u0442\u0435",
  "primer.user.headline": "\u041a\u043e\u0448\u0435\u043b\u0451\u043a, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0430\u043a\u0442\u0438\u0432\u043d\u043e \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u0434\u043e\u0441\u0442\u0438\u0447\u044c \u0446\u0435\u043b\u0435\u0439",
  "primer.user.b1": "AI Copilot \u043e\u0442\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u0435\u0442 8 \u0441\u0438\u0433\u043d\u0430\u043b\u043e\u0432 \u043d\u0430 \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0435 \u0438 \u043f\u0440\u0435\u0434\u0443\u043f\u0440\u0435\u0436\u0434\u0430\u0435\u0442 \u0434\u043e \u043f\u0435\u0440\u0435\u0440\u0430\u0441\u0445\u043e\u0434\u0430.",
  "primer.user.b2": "Autopilot \u043c\u043e\u0436\u0435\u0442 \u043f\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u043d\u0435\u0431\u043e\u043b\u044c\u0448\u0438\u0435 \u0441\u0443\u043c\u043c\u044b \u0432 \u043e\u0442\u0441\u0442\u0430\u044e\u0449\u0438\u0435 \u0446\u0435\u043b\u0438 \u2014 \u0441 \u0436\u0451\u0441\u0442\u043a\u0438\u043c\u0438 \u0434\u043d\u0435\u0432\u043d\u044b\u043c\u0438 \u043b\u0438\u043c\u0438\u0442\u0430\u043c\u0438.",
  "primer.user.b3": "Panic Freeze \u0431\u043b\u043e\u043a\u0438\u0440\u0443\u0435\u0442 \u0438\u0441\u0445\u043e\u0434\u044f\u0449\u0438\u0435 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u044b \u0432 \u043e\u0434\u0438\u043d \u0442\u0430\u043f, \u0441 5-\u043c\u0438\u043d\u0443\u0442\u043d\u044b\u043c \u043e\u043a\u043d\u043e\u043c \u043d\u0430 \u0440\u0430\u0437\u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435.",
  "primer.creator.headline": "\u0412\u0430\u0448\u0430 \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u044f \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u0432\u0430\u0448\u0438\u043c \u043a\u0440\u0435\u0434\u0438\u0442\u043e\u043c",
  "primer.creator.b1": "Trust Score \u043e\u0431\u044a\u0435\u0434\u0438\u043d\u044f\u0435\u0442 8 \u0444\u0430\u043a\u0442\u043e\u0440\u043e\u0432: QRight (IP), CyberChess, Planet \u0438 \u0431\u0430\u043d\u043a\u043e\u0432\u0441\u043a\u0443\u044e \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c.",
  "primer.creator.b2": "\u041f\u043e\u0442\u043e\u043a \u0440\u043e\u044f\u043b\u0442\u0438 \u0438\u0437 QRight \u0438\u0434\u0451\u0442 \u043f\u0440\u044f\u043c\u043e \u0432 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u2014 \u0434\u0435\u043b\u0438\u0442\u0435\u0441\u044c \u0446\u0435\u043b\u044f\u043c\u0438 \u0447\u0435\u0440\u0435\u0437 \u0433\u043e\u043b\u043e\u0433\u0440\u0430\u0444\u0438\u0447\u0435\u0441\u043a\u0438\u0439 QR.",
  "primer.creator.b3": "\u0414\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u044e\u0442 \u0442\u0438\u0440\u044b; \u0442\u0438\u0440\u044b \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u044e\u0442 \u0430\u0432\u0430\u043d\u0441\u044b \u0438 \u043f\u0440\u0438\u0432\u0438\u043b\u0435\u0433\u0438\u0438 \u0432 27 \u043c\u043e\u0434\u0443\u043b\u044f\u0445 AEVION.",
  "primer.investor.headline": "Capital-light \u0444\u0438\u043d\u0442\u0435\u0445 \u0441 ecosystem moat",
  "primer.investor.b1": "Client-side \u0441\u0443\u0432\u0435\u0440\u0435\u043d\u0438\u0442\u0435\u0442: \u0446\u0435\u043b\u0438, recurring, \u043f\u043e\u0434\u0430\u0440\u043a\u0438 \u2014 \u0432\u0441\u0451 \u043d\u0430 \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0435. \u041d\u0438\u043a\u0430\u043a\u043e\u0433\u043e vendor lock-in.",
  "primer.investor.b2": "Regulator-ready by design: QSign HMAC \u0430\u0443\u0434\u0438\u0442, Shamir SSS 2-of-3, \u0434\u043b\u044f v1 \u043d\u0435 \u043d\u0443\u0436\u043d\u0430 \u043a\u0440\u0435\u0434\u0438\u0442\u043d\u0430\u044f \u043b\u0438\u0446\u0435\u043d\u0437\u0438\u044f.",
  "primer.investor.b3": "Trust Graph \u2014 \u0440\u0430\u0441\u0442\u0443\u0449\u0438\u0439 moat: \u043a\u0430\u0436\u0434\u044b\u0439 \u0438\u0437 27 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 AEVION \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442 \u0444\u0430\u043a\u0442\u043e\u0440 Trust.",
