  // Referral landing /bank/r/[code]
  "referralLanding.headline": "\u0412\u0430\u0441 \u043f\u0440\u0438\u0433\u043b\u0430\u0441\u0438\u043b\u0438 \u0432 AEVION",
  "referralLanding.headlineNamed": "{name} \u043f\u0440\u0438\u0433\u043b\u0430\u0448\u0430\u0435\u0442 \u0432\u0430\u0441 \u0432 AEVION",
  "referralLanding.body": "\u0420\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044c \u043f\u043e \u044d\u0442\u043e\u0439 \u0441\u0441\u044b\u043b\u043a\u0435 \u0438 \u043f\u043e\u043b\u0443\u0447\u0438\u0442\u0435 +{invitee} AEC \u043d\u0430 \u043f\u0435\u0440\u0432\u043e\u0435 \u043f\u043e\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u0435. \u041f\u0440\u0438\u0433\u043b\u0430\u0441\u0438\u0432\u0448\u0438\u0439 \u043f\u043e\u043b\u0443\u0447\u0438\u0442 +{referrer} AEC \u2014 \u0441\u0442\u0438\u043c\u0443\u043b\u044b \u043f\u0440\u043e\u0437\u0440\u0430\u0447\u043d\u043e \u0441\u043e\u0432\u043f\u0430\u0434\u0430\u044e\u0442.",
