  "referralLanding.cta.continue": "\u041f\u0440\u043e\u0434\u043e\u043b\u0436\u0438\u0442\u044c \u0432 \u043a\u043e\u0448\u0435\u043b\u0451\u043a",
  "referralLanding.cta.login": "\u0423 \u043c\u0435\u043d\u044f \u0443\u0436\u0435 \u0435\u0441\u0442\u044c \u0430\u043a\u043a\u0430\u0443\u043d\u0442",
  "referralLanding.about.label": "\u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 AEVION",
  "referralLanding.about.body": "\u041a\u043e\u0448\u0435\u043b\u0451\u043a \u043d\u0430 \u0434\u043e\u0432\u0435\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u043c \u0433\u0440\u0430\u0444\u0435, \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0440\u043e\u044f\u043b\u0442\u0438 \u0437\u0430 IP, \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u043f\u043b\u0430\u0442\u0435\u0436\u0438, \u043a\u0440\u0435\u0434\u0438\u0442 \u043f\u043e trust-score \u0438 18 \u0430\u0447\u0438\u0432\u043e\u043a. 12 \u0436\u0438\u0432\u044b\u0445 MVP \u0443\u0436\u0435 \u0441\u0435\u0439\u0447\u0430\u0441.",
