  "explore.group.developers": "\u0420\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0447\u0438\u043a\u0438",
  "explore.card.about.title": "\u041e AEVION Bank",
  "explore.card.about.hint": "\u0417\u0430\u0447\u0435\u043c \u043d\u0443\u0436\u0435\u043d \u044d\u0442\u043e\u0442 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u2014 \u043a\u043e\u043c\u043f\u043e\u0437\u0438\u0446\u0438\u044f, \u043a\u0440\u0435\u0434\u0438\u0442 \u043f\u043e \u0434\u043e\u0432\u0435\u0440\u0438\u044e, \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u0434\u0435\u043d\u044c\u0433\u0438, \u0441\u0443\u0432\u0435\u0440\u0435\u043d\u0438\u0442\u0435\u0442.",
  "explore.card.trust.title": "Trust Score",
