  "explore.card.security.title": "\u041c\u043e\u0434\u0435\u043b\u044c \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u0438",
  "explore.card.security.hint": "\u041f\u044f\u0442\u044c \u0441\u043b\u043e\u0451\u0432 \u0437\u0430\u0449\u0438\u0442\u044b: \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u043e \u00b7 QSign \u00b7 \u0431\u0438\u043e\u043c\u0435\u0442\u0440\u0438\u044f \u00b7 \u0430\u043d\u043e\u043c\u0430\u043b\u0438\u0438 \u00b7 \u044d\u043a\u0441\u043f\u043e\u0440\u0442. \u0411\u0435\u0437 \u0431\u0443\u043c\u0430\u0433.",
  "explore.card.card.title": "\u041a\u0430\u0440\u0442\u0430 \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0430",
  "explore.card.card.hint": "\u0412\u0438\u0440\u0442\u0443\u0430\u043b\u044c\u043d\u0430\u044f \u043a\u0430\u0440\u0442\u0430, \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u0441\u043b\u0435\u0434\u0443\u0435\u0442 \u0437\u0430 \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u0435\u0439. \u041f\u0435\u0440\u0435\u0432\u0435\u0440\u043d\u0443\u0442\u044c \u00b7 \u0441\u043a\u0440\u044b\u0442\u044c \u00b7 \u043f\u0435\u0447\u0430\u0442\u044c.",
  "explore.card.help.title": "\u0421\u043f\u0440\u0430\u0432\u043a\u0430 \u0438 FAQ",
  "explore.card.help.hint": "25 \u043e\u0442\u0432\u0435\u0442\u043e\u0432 \u0432 \u0448\u0435\u0441\u0442\u0438 \u0440\u0430\u0437\u0434\u0435\u043b\u0430\u0445 \u043f\u0440\u043e\u0441\u0442\u044b\u043c \u044f\u0437\u044b\u043a\u043e\u043c \u2014 \u043f\u043e\u0438\u0441\u043a, \u043c\u0443\u043b\u044c\u0442\u0438\u044f\u0437\u044b\u0447\u043d\u043e\u0441\u0442\u044c.",
  "explore.card.glossary.title": "\u0413\u043b\u043e\u0441\u0441\u0430\u0440\u0438\u0439",
  "explore.card.glossary.hint": "32 \u0442\u0435\u0440\u043c\u0438\u043d\u0430 \u0432 \u0441\u0435\u043c\u0438 \u0433\u0440\u0443\u043f\u043f\u0430\u0445 \u2014 \u043a\u0430\u0436\u0434\u043e\u0435 \u043f\u043e\u043d\u044f\u0442\u0438\u0435 \u0432 \u043e\u0434\u0438\u043d \u0430\u0431\u0437\u0430\u0446.",
  "explore.card.contacts.title": "\u0410\u0434\u0440\u0435\u0441\u043d\u0430\u044f \u043a\u043d\u0438\u0433\u0430",
  "explore.card.contacts.hint": "\u0421\u043e\u0445\u0440\u0430\u043d\u0451\u043d\u043d\u044b\u0435 \u043f\u043e\u043b\u0443\u0447\u0430\u0442\u0435\u043b\u0438 \u0441 last-used \u0438 \u0441\u0447\u0451\u0442\u0447\u0438\u043a\u043e\u043c \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u043e\u0432. \u041f\u0435\u0440\u0435\u0438\u043c\u0435\u043d\u043e\u0432\u0430\u0442\u044c, \u043a\u043e\u043f\u0438\u0440\u043e\u0432\u0430\u0442\u044c id, \u0443\u0434\u0430\u043b\u0438\u0442\u044c.",
