  "explore.card.savings.hint": "Goals \u00b7 Vault \u00b7 Round-Up \u0432 \u043e\u0434\u043d\u043e\u0439 \u043f\u043e\u0437\u0438\u0446\u0438\u0438. Read-only \u0437\u0435\u0440\u043a\u0430\u043b\u043e /bank.",
