  "explore.card.circles.hint": "\u041e\u0431\u0437\u043e\u0440 \u0432\u0441\u0435\u0445 \u043e\u0431\u0449\u0438\u0445 \u0433\u0440\u0443\u043f\u043f \u043f\u043b\u0430\u0442\u0435\u0436\u0435\u0439 \u2014 \u0443\u0447\u0430\u0441\u0442\u043d\u0438\u043a\u0438, \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u044f, \u043d\u0435\u0434\u0430\u0432\u043d\u044f\u044f \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c.",
  "explore.card.insights.title": "\u0410\u043d\u0430\u043b\u0438\u0442\u0438\u043a\u0430 \u0442\u0440\u0430\u0442",
  "explore.card.insights.hint": "\u0410\u0432\u0442\u043e-\u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0437\u0430\u0446\u0438\u044f \u0440\u0430\u0441\u0445\u043e\u0434\u043e\u0432, \u0441\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u0435 \u0441 \u043f\u0440\u043e\u0448\u043b\u044b\u043c, \u0441\u0430\u043c\u0430\u044f \u043a\u0440\u0443\u043f\u043d\u0430\u044f tx, \u0442\u043e\u043f \u043f\u043e\u043b\u0443\u0447\u0430\u0442\u0435\u043b\u0435\u0439.",
  "explore.card.flow.title": "\u041f\u043e\u0442\u043e\u043a \u0434\u0435\u043d\u0435\u0433",
  "explore.card.flow.hint": "Sankey \u043f\u043e\u0441\u0442\u0443\u043f\u043b\u0435\u043d\u0438\u0439 \u0438 \u0440\u0430\u0441\u0445\u043e\u0434\u043e\u0432. \u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u0438 \u2192 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u2192 \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0438. \u041f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u043f\u0435\u0440\u0438\u043e\u0434\u0430.",
