  "explore.card.onboarding.hint": "\u041f\u044f\u0442\u044c \u0448\u0430\u0433\u043e\u0432 \u043e\u043d\u0431\u043e\u0440\u0434\u0438\u043d\u0433\u0430 \u0441 HowTo schema. \u041f\u0440\u043e\u0433\u0440\u0435\u0441\u0441 \u0445\u0440\u0430\u043d\u0438\u0442\u0441\u044f \u043d\u0430 \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0435.",
