  "explore.card.bank.hint": "\u041f\u043e\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u0435, \u043e\u0442\u043f\u0440\u0430\u0432\u043a\u0430, \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u044b\u0435, \u0446\u0435\u043b\u0438, \u0430\u0447\u0438\u0432\u043a\u0438 \u2014 \u0432\u0441\u0435 \u0444\u0438\u0447\u0438 \u043d\u0430 \u043e\u0434\u043d\u043e\u043c \u0434\u0430\u0448\u0431\u043e\u0440\u0434\u0435.",
