  "explore.card.leaderboard.hint": "\u0422\u043e\u043f \u0430\u0432\u0442\u043e\u0440\u043e\u0432, \u0447\u0435\u043c\u043f\u0438\u043e\u043d\u043e\u0432 CyberChess, \u043f\u0440\u0438\u0433\u043b\u0430\u0441\u0438\u0432\u0448\u0438\u0445 \u043f\u043e trust-\u0433\u0440\u0430\u0444\u0443.",
  "explore.card.share.title": "\u041f\u0443\u0431\u043b\u0438\u0447\u043d\u044b\u0439 \u043f\u0440\u043e\u0444\u0438\u043b\u044c",
