  "explore.card.referral.title": "\u0420\u0435\u0444\u0435\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u043b\u0435\u043d\u0434\u0438\u043d\u0433",
  "explore.card.referral.hint": "\u041c\u0430\u0440\u043a\u0435\u0442\u0438\u043d\u0433\u043e\u0432\u0430\u044f \u043a\u0430\u0440\u0442\u0430, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0432\u0438\u0434\u044f\u0442 \u043f\u0440\u0438\u0433\u043b\u0430\u0448\u0451\u043d\u043d\u044b\u0435 \u0434\u043e auth-\u0441\u0442\u0435\u043d\u044b.",
  "explore.card.gift.title": "\u041f\u043e\u043b\u0443\u0447\u0435\u043d\u0438\u0435 \u043f\u043e\u0434\u0430\u0440\u043a\u0430",
  "explore.card.gift.hint": "\u0422\u0435\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f reveal-\u0441\u0442\u0440\u0430\u043d\u0438\u0446\u0430 AEC-\u043f\u043e\u0434\u0430\u0440\u043a\u0430. \u041a\u0440\u043e\u0441\u0441-\u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u043e \u0447\u0435\u0440\u0435\u0437 \u043f\u043e\u0434\u043f\u0438\u0441\u0430\u043d\u043d\u044b\u0439 URL.",
