  "explore.card.notifications.hint": "\u0410\u0447\u0438\u0432\u043a\u0438, \u043f\u043e\u0434\u043f\u0438\u0441\u0438, \u0430\u043d\u043e\u043c\u0430\u043b\u0438\u0438, \u0441\u043e\u0431\u044b\u0442\u0438\u044f \u043f\u043e\u0434\u0430\u0440\u043a\u043e\u0432 \u2014 \u0438\u0437 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044f.",
