  "explore.card.recurring.hint": "\u0410\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u044b: \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435, \u043d\u0435\u0434\u0435\u043b\u044c\u043d\u044b\u0435, \u0434\u0432\u0443\u0445\u043d\u0435\u0434\u0435\u043b\u044c\u043d\u044b\u0435, \u0435\u0436\u0435\u043c\u0435\u0441\u044f\u0447\u043d\u044b\u0435. \u041f\u0430\u0443\u0437\u0430 \u0438\u043b\u0438 \u043e\u0442\u043c\u0435\u043d\u0430 \u0432 \u043b\u044e\u0431\u043e\u0435 \u0432\u0440\u0435\u043c\u044f.",
  "explore.card.budget.title": "\u041c\u0435\u0441\u044f\u0447\u043d\u044b\u0439 \u0431\u044e\u0434\u0436\u0435\u0442",
