  "explore.card.subscriptions.title": "\u0421\u043a\u0430\u043d\u0435\u0440 \u043f\u043e\u0434\u043f\u0438\u0441\u043e\u043a",
  "explore.card.subscriptions.hint": "\u0410\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u043f\u043e\u043c\u0435\u0447\u0430\u0435\u0442 \u0441\u0442\u044b\u043b\u044b\u0435, \u0434\u043e\u0440\u043e\u0433\u0438\u0435 \u0438 \u0434\u0443\u0431\u043b\u0438\u0440\u0443\u044e\u0449\u0438\u0435\u0441\u044f \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u044b\u0435 \u0441\u043f\u0438\u0441\u0430\u043d\u0438\u044f. \u041f\u0430\u0443\u0437\u0430 \u0432 \u043e\u0434\u0438\u043d \u0442\u0430\u043f.",
