  "budgetPage.statusBody.ontrack": "\u041f\u0440\u0438 \u0442\u0430\u043a\u043e\u043c \u0442\u0435\u043c\u043f\u0435 \u0432\u044b \u0432\u044b\u0439\u0434\u0435\u0442\u0435 \u043d\u0430 ~{projected} \u2014 \u043d\u0438\u0436\u0435 {cap}. \u0422\u0430\u043a \u0434\u0435\u0440\u0436\u0430\u0442\u044c.",
