  "forecastPage.lede": "\u041a\u043e\u043d\u0441\u0435\u0440\u0432\u0430\u0442\u0438\u0432\u043d\u044b\u0439, \u0440\u0435\u0430\u043b\u0438\u0441\u0442\u0438\u0447\u043d\u044b\u0439 \u0438 \u043e\u043f\u0442\u0438\u043c\u0438\u0441\u0442\u0438\u0447\u043d\u044b\u0439 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u044b \u043d\u0430 \u0433\u043e\u0440\u0438\u0437\u043e\u043d\u0442\u0430\u0445 30 / 90 / 365 \u0434\u043d\u0435\u0439. ETA \u0434\u043e \u0446\u0435\u043b\u0435\u0439 \u0432\u044b\u0432\u043e\u0434\u0438\u0442\u0441\u044f \u0438\u0437 \u0432\u0430\u0448\u0438\u0445 \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u0445 \u043f\u043e\u0442\u043e\u043a\u043e\u0432 \u0434\u043e\u0445\u043e\u0434\u0430 \u2014 royalty, \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u0438 \u0448\u0430\u0445\u043c\u0430\u0442\u044b.",
  "forecastPage.empty.title": "\u041a\u043e\u0448\u0435\u043b\u044c\u043a\u0430 \u043f\u043e\u043a\u0430 \u043d\u0435\u0442",
  "forecastPage.empty.body": "\u0414\u043b\u044f \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0430 \u043d\u0443\u0436\u0435\u043d \u0441\u0447\u0451\u0442. \u041e\u0442\u043a\u0440\u043e\u0439\u0442\u0435 \u043a\u043e\u0448\u0435\u043b\u0451\u043a, \u0437\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044c \u2014 \u0438 \u043f\u0440\u043e\u0435\u043a\u0446\u0438\u044f \u043f\u043e\u044f\u0432\u0438\u0442\u0441\u044f \u0437\u0434\u0435\u0441\u044c.",
  "forecastPage.method.kicker": "\u041c\u0435\u0442\u043e\u0434\u0438\u043a\u0430",
  "forecastPage.method.body": "\u041a\u0430\u0436\u0434\u044b\u0439 \u0441\u0446\u0435\u043d\u0430\u0440\u0438\u0439 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0435\u0442 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u043c\u043d\u043e\u0436\u0438\u0442\u0435\u043b\u044c \u043a \u0432\u0430\u0448\u0435\u043c\u0443 \u0442\u0435\u043a\u0443\u0449\u0435\u043c\u0443 \u043c\u0435\u0441\u044f\u0447\u043d\u043e\u043c\u0443 \u043f\u0440\u0438\u0442\u043e\u043a\u0443 \u0438\u0437 \u0442\u0440\u0451\u0445 \u043f\u043e\u0442\u043e\u043a\u043e\u0432 \u0434\u043e\u0445\u043e\u0434\u0430. ETA \u0440\u0430\u0441\u0441\u0447\u0438\u0442\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0438\u043d\u0442\u0435\u0433\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435\u043c \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0438\u0440\u0443\u0435\u043c\u043e\u0433\u043e \u0431\u0430\u043b\u0430\u043d\u0441\u0430 \u0434\u043e \u043a\u0430\u0436\u0434\u043e\u0439 \u0446\u0435\u043b\u0438. \u0427\u0438\u0441\u043b\u0430 \u0438\u043b\u043b\u044e\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u044b\u0435 \u2014 \u043e\u043d\u0438 \u043f\u0440\u0435\u0434\u043f\u043e\u043b\u0430\u0433\u0430\u044e\u0442, \u0447\u0442\u043e \u0442\u0435\u043a\u0443\u0449\u0435\u0435 \u043f\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u043d\u0435 \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f.",
