  // About /bank/about
  "about.backToBank": "\u041d\u0430\u0437\u0430\u0434 \u0432 AEVION Bank",
  "about.headline": "\u041a\u043e\u0448\u0435\u043b\u0451\u043a \u0434\u043b\u044f \u0433\u0440\u0430\u0444\u0430 \u0434\u043e\u0432\u0435\u0440\u0438\u044f",
  "about.lede": "AEVION Bank \u2014 \u044d\u043a\u043e\u043d\u043e\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u043a\u043e\u0440\u0435\u043d\u044c creator-first \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u044b. \u0414\u0435\u043d\u044c\u0433\u0438 \u043a\u043e\u043c\u043f\u043e\u0437\u0438\u0440\u0443\u044e\u0442\u0441\u044f \u0441 \u0442\u0435\u043c, \u0447\u0442\u043e \u0432\u044b \u0441\u043e\u0437\u0434\u0430\u0451\u0442\u0435: \u0440\u043e\u044f\u043b\u0442\u0438 \u043f\u0440\u0438\u0445\u043e\u0434\u044f\u0442 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438, \u043a\u0440\u0435\u0434\u0438\u0442 \u0440\u0430\u0441\u0442\u0451\u0442 \u0441 \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u0435\u0439, \u0430 \u043b\u044e\u0431\u0430\u044f \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u0430\u044f \u0441\u0432\u044f\u0437\u044c \u043c\u043e\u0436\u0435\u0442 \u043d\u0435\u0441\u0442\u0438 \u0446\u0435\u043d\u043d\u043e\u0441\u0442\u044c.",
  "about.s1.kicker": "\u041a\u043e\u043c\u043f\u043e\u0437\u0438\u0446\u0438\u044f",
  "about.s1.title": "\u0414\u0435\u043d\u044c\u0433\u0438 \u0442\u0430\u043c, \u0433\u0434\u0435 \u0442\u0432\u043e\u0440\u0447\u0435\u0441\u0442\u0432\u043e",
  "about.s1.body": "QRight \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442 \u0432\u0430\u0448 IP \u0438 \u0441\u0440\u0430\u0437\u0443 \u043b\u044c\u0451\u0442 \u0440\u043e\u044f\u043b\u0442\u0438 \u0432 \u043a\u043e\u0448\u0435\u043b\u0451\u043a. CyberChess \u0437\u0430\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u043f\u0440\u0438\u0437\u043e\u0432\u044b\u0435 \u0432 \u0431\u0430\u043b\u0430\u043d\u0441. Planet-\u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442\u044b \u043a\u043e\u043f\u044f\u0442 Trust Score. Bank \u2014 \u043d\u0435 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u043e\u0435 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435, \u0430 \u0441\u043b\u043e\u0439, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0434\u0435\u043b\u0430\u0435\u0442 \u0432\u0441\u0451 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0435 \u0441\u0442\u043e\u044f\u0449\u0438\u043c.",
  "about.s2.kicker": "Trust > \u0437\u0430\u043b\u043e\u0433",
  "about.s2.title": "\u041a\u0440\u0435\u0434\u0438\u0442 \u043f\u043e \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u0438, \u043d\u0435 \u043f\u043e \u0431\u0443\u043c\u0430\u0433\u0430\u043c",
  "about.s2.body": "\u0410\u0432\u0430\u043d\u0441 \u0437\u0430\u0440\u043f\u043b\u0430\u0442\u044b \u0440\u0430\u0437\u0431\u043b\u043e\u043a\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u043f\u043e \u043c\u0435\u0440\u0435 \u0440\u043e\u0441\u0442\u0430 Trust Score \u2014 \u043e\u043d \u043a\u043e\u043f\u0438\u0442\u0441\u044f \u0438\u0437 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0439, \u043f\u043e\u0434\u043f\u0438\u0441\u0435\u0439, \u043f\u043e\u0433\u0430\u0448\u0435\u043d\u043d\u044b\u0445 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432 \u0438 \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u0438 \u0432 \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u0435. Trusted \u043f\u043e\u043b\u0443\u0447\u0430\u044e\u0442 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u043e 500 AEC, Elite \u2014 2000. \u0411\u0435\u0437 \u0442\u0435\u0430\u0442\u0440\u0430 KYC \u0438 \u00ab\u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0435 \u0447\u0435\u0440\u0435\u0437 \u0442\u0440\u0438 \u0434\u043d\u044f\u00bb.",
  "about.s3.kicker": "\u0421\u043e\u0446\u0438\u0430\u043b\u043a\u0430",
  "about.s3.title": "\u041b\u044e\u0431\u043e\u0435 \u0432\u0437\u0430\u0438\u043c\u043e\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u043c\u043e\u0436\u0435\u0442 \u043d\u0435\u0441\u0442\u0438 \u0434\u0435\u043d\u044c\u0433\u0438",
  "about.s3.body": "\u0420\u0430\u0437\u0434\u0435\u043b\u0438\u0442\u0435 \u0441\u0447\u0451\u0442 \u0432 \u0442\u0440\u0438 \u0442\u0430\u043f\u0430. \u041e\u0442\u043f\u0440\u0430\u0432\u044c\u0442\u0435 \u0442\u0435\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u043e\u0442\u043a\u0440\u044b\u0442\u043a\u0443 \u0441 \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u0435\u043c. \u041e\u0441\u0442\u0430\u0432\u044c\u0442\u0435 payment request \u0432 \u0433\u0440\u0443\u043f\u043f\u043e\u0432\u043e\u043c circle. \u0417\u0430\u043f\u043b\u0430\u043d\u0438\u0440\u0443\u0439\u0442\u0435 \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u044b\u0439 \u043f\u0435\u0440\u0435\u0432\u043e\u0434, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0441\u0430\u043c \u0441\u0442\u0430\u0432\u0438\u0442\u0441\u044f \u043d\u0430 \u043f\u0430\u0443\u0437\u0443, \u0435\u0441\u043b\u0438 \u0431\u0430\u043b\u0430\u043d\u0441 \u043f\u0440\u043e\u0441\u0435\u043b. \u041a\u043e\u0448\u0435\u043b\u0451\u043a \u0442\u0430\u043c, \u0433\u0434\u0435 \u0443\u0436\u0435 \u0438\u0434\u0443\u0442 \u0440\u0430\u0437\u0433\u043e\u0432\u043e\u0440\u044b.",
  "about.s4.kicker": "\u0421\u0443\u0432\u0435\u0440\u0435\u043d\u0438\u0442\u0435\u0442",
  "about.s4.title": "\u0412\u0430\u0448\u0438 \u0434\u0430\u043d\u043d\u044b\u0435, \u0432\u0430\u0448\u0435 \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u043e, \u0432\u0430\u0448 \u0432\u044b\u0431\u043e\u0440",
  "about.s4.body": "\u0411\u0438\u043e\u043c\u0435\u0442\u0440\u0438\u044f \u043d\u0430 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u0430\u0445 \u0432\u044b\u0448\u0435 \u043f\u043e\u0440\u043e\u0433\u0430. QSign \u043f\u043e\u0434\u043f\u0438\u0441\u044b\u0432\u0430\u0435\u0442 \u043a\u0430\u0436\u0434\u0443\u044e \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044e \u0432\u0430\u0448\u0438\u043c Ed25519. Activity timeline \u043b\u043e\u0432\u0438\u0442 \u0430\u043d\u043e\u043c\u0430\u043b\u0438\u0438 \u0434\u043e \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u043e\u043d\u0438 \u0434\u043e\u0435\u0434\u0443\u0442 \u0434\u043e \u0432\u044b\u043f\u0438\u0441\u043a\u0438. \u042d\u043a\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u0443\u0439\u0442\u0435 \u0432\u0435\u0441\u044c \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u043e\u0434\u043d\u0438\u043c JSON \u2014 \u043d\u0438\u043a\u0430\u043a\u043e\u0433\u043e vendor lock-in.",
  "about.cta.kicker": "Live MVP",
  "about.cta.title": "\u042d\u0442\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u0443\u0436\u0435 \u0441\u0435\u0433\u043e\u0434\u043d\u044f.",
  "about.cta.body": "12 \u0436\u0438\u0432\u044b\u0445 \u043c\u043e\u0434\u0443\u043b\u0435\u0439. 18 \u0431\u0430\u043d\u043a\u043e\u0432\u0441\u043a\u0438\u0445 \u0444\u0438\u0447. 11 \u043f\u043e\u0434\u043c\u0430\u0440\u0448\u0440\u0443\u0442\u043e\u0432. Multilingual EN / RU / KZ. \u0423\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u043a\u0430\u043a PWA. \u0413\u0440\u0430\u0444 \u0434\u043e\u0432\u0435\u0440\u0438\u044f \u0436\u0438\u0432\u0451\u0442.",
  "about.cta.openBank": "\u041e\u0442\u043a\u0440\u044b\u0442\u044c \u043c\u043e\u0439 \u043a\u043e\u0448\u0435\u043b\u0451\u043a",
