  "trust.page.wins.title": "\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0439 \u043f\u0443\u0442\u044c \u043a \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0435\u043c\u0443 \u0443\u0440\u043e\u0432\u043d\u044e",
  "trust.page.method.kicker": "\u041c\u0435\u0442\u043e\u0434\u043e\u043b\u043e\u0433\u0438\u044f",
  "trust.page.method.title": "\u041a\u0430\u043a \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u0431\u0430\u043b\u043b",
  "trust.page.method.body": "\u041a\u0430\u0436\u0434\u044b\u0439 \u0444\u0430\u043a\u0442\u043e\u0440 \u0434\u0430\u0451\u0442 0\u2013100 \u0431\u0430\u043b\u043b\u043e\u0432 \u0447\u0435\u0440\u0435\u0437 \u0441\u0443\u0431\u043b\u0438\u043d\u0435\u0439\u043d\u0443\u044e \u043a\u0440\u0438\u0432\u0443\u044e \u2014 \u0440\u0430\u043d\u043d\u0438\u0439 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441 \u0437\u0430\u043c\u0435\u0442\u0435\u043d \u0441\u0440\u0430\u0437\u0443, \u0434\u0430\u043b\u044c\u0448\u0435 \u0432\u044b\u0445\u043e\u0434 \u043d\u0430 \u043f\u043b\u0430\u0442\u043e \u043a \u043c\u044f\u0433\u043a\u043e\u0439 \u0446\u0435\u043b\u0438. \u0424\u0430\u043a\u0442\u043e\u0440\u044b \u0441\u043b\u0438\u0432\u0430\u044e\u0442\u0441\u044f \u0432\u0437\u0432\u0435\u0448\u0435\u043d\u043d\u044b\u043c \u0441\u0440\u0435\u0434\u043d\u0438\u043c (\u0431\u0430\u043d\u043a\u0438\u043d\u0433 0.8\u20131.2, \u044d\u043a\u043e 0.7\u20131.2). +3 \u0431\u043e\u043d\u0443\u0441 \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043b\u044e\u0431\u043e\u0439 \u0444\u0430\u043a\u0442\u043e\u0440 \u0434\u043e\u0441\u0442\u0438\u0433\u0430\u0435\u0442 30 \u2014 \u043d\u043e\u0432\u0435\u043d\u044c\u043a\u0438\u0435 \u043d\u0435 \u0441\u0438\u0434\u044f\u0442 \u043d\u0430 \u043d\u0443\u043b\u0435. \u0413\u0435\u0439\u0442\u044b \u0443\u0440\u043e\u0432\u043d\u0435\u0439: 0 / 20 / 50 / 80. \u0420\u0430\u0441\u0447\u0451\u0442 \u0432\u0435\u0441\u044c \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u2014 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u0438\u0437 \u0432\u0430\u0448\u0435\u0433\u043e \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0430 \u043d\u0435 \u0432\u044b\u0445\u043e\u0434\u0438\u0442.",
