  "receipt.notFound.body": "\u041e\u043f\u0435\u0440\u0430\u0446\u0438\u044f {id} \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u043c \u0436\u0443\u0440\u043d\u0430\u043b\u0435. \u0427\u0435\u043a \u0440\u0435\u043d\u0434\u0435\u0440\u0438\u0442\u0441\u044f \u0438\u0437 \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u043c \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0435 \u2014 \u043d\u0430 \u0434\u0440\u0443\u0433\u043e\u043c \u0431\u0440\u0430\u0443\u0437\u0435\u0440\u0435 \u0438\u0441\u0442\u043e\u0440\u0438\u0438 \u043d\u0435\u0442.",

  // Card /bank/card
  "card.kicker": "\u041a\u0430\u0440\u0442\u0430 \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0430",
  "card.headline": "\u041a\u0430\u0440\u0442\u0430 \u043d\u0430 \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u0438.",
  "card.lede": "\u041a\u0430\u0440\u0442\u0430 AEVION Bank \u2014 \u0432\u0438\u0440\u0442\u0443\u0430\u043b\u044c\u043d\u044b\u0439 \u0430\u0440\u0442\u0435\u0444\u0430\u043a\u0442: \u043e\u0434\u043d\u0438\u043c \u0432\u0437\u0433\u043b\u044f\u0434\u043e\u043c \u0432\u0438\u0434\u043d\u043e \u0432\u0430\u0448 wallet-identity, \u0438 \u0438\u043c \u043c\u043e\u0436\u043d\u043e \u043f\u043e\u0434\u0435\u043b\u0438\u0442\u044c\u0441\u044f. \u0423\u0440\u043e\u0432\u0435\u043d\u044c \u2014 \u044d\u0442\u043e \u0432\u0430\u0448 Trust Score; \u0433\u043e\u043b\u043e\u0433\u0440\u0430\u0444\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0444\u043e\u043b\u044c\u0433\u0430 \u0435\u0433\u043e \u043f\u043e\u0434\u0441\u0432\u0435\u0447\u0438\u0432\u0430\u0435\u0442. \u0411\u0435\u0437 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430, \u0431\u0435\u0437 \u0434\u043e\u0441\u0442\u0430\u0432\u043a\u0438.",
  "card.flipAria": "\u041f\u0435\u0440\u0435\u0432\u0435\u0440\u043d\u0443\u0442\u044c \u043a\u0430\u0440\u0442\u0443, \u0447\u0442\u043e\u0431\u044b \u0443\u0432\u0438\u0434\u0435\u0442\u044c \u043e\u0431\u0440\u0430\u0442\u043d\u0443\u044e \u0441\u0442\u043e\u0440\u043e\u043d\u0443",
  "card.member": "\u0412\u043b\u0430\u0434\u0435\u043b\u0435\u0446",
  "card.memberSince": "\u0421",
  "card.back.title": "\u041f\u0440\u043e\u0432\u0435\u0440\u0438\u0442\u044c \u0432 AEVION",
  "card.back.body1": "\u041e\u0442\u0441\u043a\u0430\u043d\u0438\u0440\u0443\u0439\u0442\u0435 QR \u2014 \u043e\u0442\u043a\u0440\u043e\u0435\u0442\u0441\u044f \u043f\u0443\u0431\u043b\u0438\u0447\u043d\u044b\u0439 \u043f\u0440\u043e\u0444\u0438\u043b\u044c \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0430. \u0423\u0440\u043e\u0432\u0435\u043d\u044c \u0438 Trust Score \u0440\u0435\u043d\u0434\u0435\u0440\u044f\u0442\u0441\u044f \u0438\u0437 \u0442\u043e\u0433\u043e \u0436\u0435 \u0436\u0443\u0440\u043d\u0430\u043b\u0430, \u0447\u0442\u043e \u0438 \u0432\u043d\u0443\u0442\u0440\u0438 \u0431\u0430\u043d\u043a\u0430.",
  "card.back.body2": "\u041a\u0430\u0440\u0442\u0430 \u043d\u0435\u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u043c\u0430\u044f, \u043f\u0440\u0438\u0432\u044f\u0437\u0430\u043d\u0430 \u043a \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0443 \u0441 \u043a\u043b\u044e\u0447\u0435\u0432\u043e\u0439 \u043f\u0430\u0440\u043e\u0439.",
