  "card.action.flip": "\u041f\u0435\u0440\u0435\u0432\u0435\u0440\u043d\u0443\u0442\u044c",
  "card.action.front": "\u041f\u043e\u043a\u0430\u0437\u0430\u0442\u044c \u043b\u0438\u0446\u043e",
