  "contacts.action.edit": "\u041f\u0435\u0440\u0435\u0438\u043c\u0435\u043d\u043e\u0432\u0430\u0442\u044c",
  "contacts.action.remove": "\u0423\u0434\u0430\u043b\u0438\u0442\u044c",
  "contacts.edit.aria": "\u0420\u0435\u0434\u0430\u043a\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043d\u0438\u043a",
  "contacts.confirmRemove": "\u0423\u0434\u0430\u043b\u0438\u0442\u044c \u043a\u043e\u043d\u0442\u0430\u043a\u0442? \u041e\u043d \u0438\u0441\u0447\u0435\u0437\u043d\u0435\u0442 \u0438\u0437 \u0430\u0432\u0442\u043e\u043a\u043e\u043c\u043f\u043b\u0438\u0442\u0430 \u043d\u0430 /bank.",
  "contacts.empty.title": "\u041a\u043e\u043d\u0442\u0430\u043a\u0442\u043e\u0432 \u043f\u043e\u043a\u0430 \u043d\u0435\u0442.",
  "contacts.empty.body": "\u041a\u043e\u0433\u0434\u0430 \u043e\u0442\u043f\u0440\u0430\u0432\u0438\u0442\u0435 \u043a\u043e\u043c\u0443-\u0442\u043e AEC, \u0441\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u0435 \u0435\u0433\u043e \u0441 \u043d\u0438\u043a\u043e\u043c \u2014 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u043f\u043e\u0434\u0441\u0442\u0430\u0432\u0438\u0442 \u0430\u0432\u0442\u043e\u043a\u043e\u043c\u043f\u043b\u0438\u0442 \u0432 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0438\u0439 \u0440\u0430\u0437.",
  "contacts.searchEmpty.title": "\u041d\u0435 \u043d\u0430\u0439\u0434\u0435\u043d\u043e.",
  "contacts.searchEmpty.body": "\u041d\u0438\u0447\u0435\u0433\u043e \u043f\u043e \u00ab{q}\u00bb. \u041f\u043e\u043f\u0440\u043e\u0431\u0443\u0439\u0442\u0435 \u043a\u043e\u0440\u043e\u0447\u0435 \u0438\u043b\u0438 \u043e\u0447\u0438\u0441\u0442\u0438\u0442\u0435 \u043f\u043e\u0438\u0441\u043a.",
  "contacts.privacy.title": "\u0425\u0440\u0430\u043d\u0438\u0442\u0441\u044f \u043d\u0430 \u044d\u0442\u043e\u043c \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0435.",
  "contacts.privacy.body": "\u041a\u043e\u043d\u0442\u0430\u043a\u0442\u044b \u0436\u0438\u0432\u0443\u0442 \u0432 localStorage \u0438 \u043d\u0435 \u0443\u0445\u043e\u0434\u044f\u0442 \u043d\u0430 \u0441\u0435\u0440\u0432\u0435\u0440. \u042d\u043a\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u0443\u0439\u0442\u0435 \u0447\u0435\u0440\u0435\u0437 Help \u2192 \u042d\u043a\u0441\u043f\u043e\u0440\u0442 \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0430 \u0434\u043b\u044f \u0431\u044d\u043a\u0430\u043f\u0430.",

