  "onboarding.markUndone": "\u041e\u0442\u043c\u0435\u043d\u0438\u0442\u044c",
  "onboarding.auth.title": "\u0412\u043e\u0439\u0434\u0438\u0442\u0435 \u0438\u043b\u0438 \u0441\u043e\u0437\u0434\u0430\u0439\u0442\u0435 \u0430\u043a\u043a\u0430\u0443\u043d\u0442",
  "onboarding.auth.body": "\u041e\u0442\u043a\u0440\u043e\u0439\u0442\u0435 /auth \u0438 \u0437\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044c \u043f\u043e email \u0438 \u043f\u0430\u0440\u043e\u043b\u044e. \u042f\u043a\u043e\u0440\u044c \u0430\u043a\u043a\u0430\u0443\u043d\u0442\u0430 \u0436\u0438\u0432\u0451\u0442 \u043d\u0430 \u0431\u044d\u043a\u0435\u043d\u0434\u0435 AEVION; \u0432\u0441\u0451 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0435 \u2014 \u043d\u0430 \u044d\u0442\u043e\u043c \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0435.",
  "onboarding.auth.cta": "\u041e\u0442\u043a\u0440\u044b\u0442\u044c /auth",
  "onboarding.topup.title": "\u041f\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435 \u043a\u043e\u0448\u0435\u043b\u0451\u043a",
  "onboarding.topup.body": "\u041e\u0442\u043a\u0440\u043e\u0439\u0442\u0435 \u043a\u043e\u0448\u0435\u043b\u0451\u043a, \u043d\u0430\u0439\u0434\u0438\u0442\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0443 Top-up, \u0432\u0432\u0435\u0434\u0438\u0442\u0435 \u0441\u0443\u043c\u043c\u0443 \u0432 AEC \u0438 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0434\u0438\u0442\u0435. Pre-launch \u2014 \u0434\u0435\u043c\u043e; \u043f\u0440\u043e\u0434\u0430\u043a\u0448\u043d-\u0440\u0435\u043b\u044c\u0441\u044b \u043f\u043e\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u044f \u0435\u0434\u0443\u0442 \u0441 \u0438\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0435\u0439 \u0431\u044d\u043a\u0435\u043d\u0434\u0430.",
  "onboarding.topup.cta": "\u041e\u0442\u043a\u0440\u044b\u0442\u044c \u043a\u043e\u0448\u0435\u043b\u0451\u043a",
  "onboarding.send.title": "\u041e\u0442\u043f\u0440\u0430\u0432\u044c\u0442\u0435 \u043f\u0435\u0440\u0432\u044b\u0435 AEC",
  "onboarding.send.body": "\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0434\u043e\u0431\u0430\u0432\u044c\u0442\u0435 \u043f\u043e\u043b\u0443\u0447\u0430\u0442\u0435\u043b\u044f \u0432 \u0430\u0434\u0440\u0435\u0441\u043d\u0443\u044e \u043a\u043d\u0438\u0433\u0443 \u2014 \u0441\u043a\u043e\u043f\u0438\u0440\u0443\u0439\u0442\u0435 account-id \u0438\u043b\u0438 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 email. \u041f\u043e\u0442\u043e\u043c \u043e\u0442\u043f\u0440\u0430\u0432\u044c\u0442\u0435 \u043b\u044e\u0431\u0443\u044e \u0441\u0443\u043c\u043c\u0443; \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f \u0441\u0440\u0430\u0437\u0443 \u043f\u043e\u0434\u043f\u0438\u0441\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0447\u0435\u0440\u0435\u0437 QSign.",
  "onboarding.send.cta": "\u0410\u0434\u0440\u0435\u0441\u043d\u0430\u044f \u043a\u043d\u0438\u0433\u0430",
  "onboarding.save.title": "\u041f\u043e\u0441\u0442\u0430\u0432\u044c\u0442\u0435 \u0446\u0435\u043b\u044c",
  "onboarding.save.body": "\u041e\u0442\u043a\u0440\u043e\u0439\u0442\u0435 \u0434\u0430\u0448\u0431\u043e\u0440\u0434 \u0441\u0431\u0435\u0440\u0435\u0436\u0435\u043d\u0438\u0439 \u0438 \u0441\u043e\u0437\u0434\u0430\u0439\u0442\u0435 Goal \u2014 \u043d\u0430\u0437\u043e\u0432\u0438\u0442\u0435, \u0437\u0430\u0434\u0430\u0439\u0442\u0435 \u0441\u0443\u043c\u043c\u0443, \u043e\u043f\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e \u0434\u0435\u0434\u043b\u0430\u0439\u043d. \u0426\u0435\u043b\u0438 \u043d\u0435 \u0431\u043b\u043e\u043a\u0438\u0440\u0443\u044e\u0442 \u0434\u0435\u043d\u044c\u0433\u0438; \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u0440\u0435\u043a\u0430\u044e\u0442 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441.",
  "onboarding.save.cta": "\u0414\u0430\u0448\u0431\u043e\u0440\u0434 \u0441\u0431\u0435\u0440\u0435\u0436\u0435\u043d\u0438\u0439",
  "onboarding.trust.title": "\u0417\u0430\u0440\u0430\u0431\u043e\u0442\u0430\u0439\u0442\u0435 \u043f\u0435\u0440\u0432\u044b\u0439 Trust-\u0443\u0440\u043e\u0432\u0435\u043d\u044c",
  "onboarding.trust.body": "Trust Score \u0440\u0430\u0441\u0442\u0451\u0442 \u043f\u043e \u043c\u0435\u0440\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u044f. \u041f\u043e\u0441\u043b\u0435 \u043f\u0435\u0440\u0432\u043e\u0433\u043e \u043f\u043e\u0434\u043f\u0438\u0441\u0430\u043d\u043d\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u0430 + \u043f\u0430\u0440\u044b \u0434\u043d\u0435\u0439 \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u0438 \u0432\u044b \u0443\u0439\u0434\u0451\u0442\u0435 \u0438\u0437 New \u0432 Growing \u2014 \u0438 \u043e\u0442\u043a\u0440\u043e\u0435\u0442\u0435 Salary Advance.",
  "onboarding.trust.cta": "\u0414\u0435\u0442\u0430\u043b\u0438 Trust Score",
  "onboarding.allDone.kicker": "\u0414\u043e\u0431\u0440\u043e \u043f\u043e\u0436\u0430\u043b\u043e\u0432\u0430\u0442\u044c \u0432 \u0433\u0440\u0430\u0444 \u0434\u043e\u0432\u0435\u0440\u0438\u044f",
  "onboarding.allDone.title": "\u0413\u043e\u0442\u043e\u0432\u043e. \u041a\u043e\u0448\u0435\u043b\u0451\u043a \u0442\u0435\u043f\u0435\u0440\u044c \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u043d\u0430 \u0432\u0430\u0441.",
  "onboarding.allDone.body": "\u041a\u0430\u0436\u0434\u0430\u044f \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f \u043e\u0442\u0441\u044e\u0434\u0430 \u0441\u0442\u0440\u043e\u0438\u0442 \u0432\u0430\u0448 Trust Score, \u0437\u0430\u043f\u043e\u043b\u043d\u044f\u0435\u0442 \u0436\u0443\u0440\u043d\u0430\u043b \u0430\u0443\u0434\u0438\u0442\u0430 \u0438 \u0444\u043e\u0440\u043c\u0438\u0440\u0443\u0435\u0442 \u043b\u0438\u043c\u0438\u0442\u044b, \u043d\u0430 \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u0433\u043e\u0442\u043e\u0432 \u0432\u0430\u0441 \u0434\u043e\u0432\u0435\u0440\u044f\u0442\u044c. \u0418\u0437\u0443\u0447\u0438\u0442\u0435 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0438.",

  // Insights /bank/insights
  "insightsPage.kicker": "\u0410\u043d\u0430\u043b\u0438\u0442\u0438\u043a\u0430 \u0442\u0440\u0430\u0442",
  "insightsPage.headline": "\u041a\u0443\u0434\u0430 \u0443\u0445\u043e\u0434\u044f\u0442 \u0434\u0435\u043d\u044c\u0433\u0438.",
  "insightsPage.lede": "\u0410\u0432\u0442\u043e-\u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0437\u0430\u0446\u0438\u044f \u0438\u0441\u0445\u043e\u0434\u044f\u0449\u0438\u0445 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u043e\u0432, \u0441\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u0435 \u0441 \u043f\u0440\u043e\u0448\u043b\u044b\u043c \u043f\u0435\u0440\u0438\u043e\u0434\u043e\u043c, \u0441\u0430\u043c\u0430\u044f \u043a\u0440\u0443\u043f\u043d\u0430\u044f \u0442\u0440\u0430\u043d\u0437\u0430\u043a\u0446\u0438\u044f \u0438 \u043a\u043e\u043c\u0443 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435 \u0447\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e. \u0421\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e \u0438\u0437 \u0430\u0443\u0434\u0438\u0442-\u0436\u0443\u0440\u043d\u0430\u043b\u0430 \u2014 \u0434\u0430\u043d\u043d\u044b\u0435 \u043e \u0442\u0440\u0430\u0442\u0430\u0445 \u043d\u0438\u043a\u0443\u0434\u0430 \u043d\u0435 \u0443\u0445\u043e\u0434\u044f\u0442.",
  "insightsPage.periodAria": "\u041f\u0435\u0440\u0438\u043e\u0434 \u0438\u043d\u0441\u0430\u0439\u0442\u043e\u0432",
  "insightsPage.total.kicker": "\u0412\u0441\u0435\u0433\u043e \u043f\u043e\u0442\u0440\u0430\u0447\u0435\u043d\u043e \u00b7 {period}",
