  "insightsPage.recipients.unknown": "\u041d\u0435\u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0439 \u043f\u043e\u043b\u0443\u0447\u0430\u0442\u0435\u043b\u044c",
  "insightsPage.empty.title": "\u0418\u0441\u0445\u043e\u0434\u044f\u0449\u0438\u0445 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u043e\u0432 \u0432 \u044d\u0442\u043e\u043c \u043f\u0435\u0440\u0438\u043e\u0434\u0435 \u043d\u0435\u0442.",
  "insightsPage.empty.body": "\u041e\u0442\u043f\u0440\u0430\u0432\u044c\u0442\u0435 \u043f\u0435\u0440\u0432\u044b\u0435 AEC \u0438\u0437 \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0430 \u2014 \u0438\u043d\u0441\u0430\u0439\u0442\u044b \u043f\u043e\u044f\u0432\u044f\u0442\u0441\u044f \u0437\u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u0435\u043a\u0443\u043d\u0434 \u0438\u0437 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0430\u0443\u0434\u0438\u0442-\u0436\u0443\u0440\u043d\u0430\u043b\u0430.",
