  "insightsPage.cta.title": "\u0412\u044b\u043f\u0438\u0441\u043a\u0430 \u0438 \u0441\u0431\u0435\u0440\u0435\u0436\u0435\u043d\u0438\u044f \u2014 \u0442\u0435 \u0436\u0435 \u0434\u0430\u043d\u043d\u044b\u0435, \u0434\u0440\u0443\u0433\u0438\u0435 \u0441\u0440\u0435\u0437\u044b.",
