  // Flow /bank/flow
  "flowPage.kicker": "\u041f\u043e\u0442\u043e\u043a \u0434\u0435\u043d\u0435\u0433",
  "flowPage.headline": "\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u0438 \u2192 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u2192 \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0438.",
  "flowPage.lede": "Sankey-\u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0430: \u0432\u0445\u043e\u0434\u044b \u0441\u043b\u0435\u0432\u0430, \u0432\u044b\u0445\u043e\u0434\u044b \u0441\u043f\u0440\u0430\u0432\u0430. \u041b\u0435\u043d\u0442\u044b \u043c\u0435\u0436\u0434\u0443 \u043d\u0438\u043c\u0438 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442, \u043a\u0430\u043a \u0434\u0435\u043d\u044c\u0433\u0438 \u043e\u0442 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u0430 \u0440\u0430\u0441\u043f\u0440\u0435\u0434\u0435\u043b\u044f\u044e\u0442\u0441\u044f \u043f\u0440\u043e\u043f\u043e\u0440\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e \u043c\u0435\u0436\u0434\u0443 \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u044f\u043c\u0438 \u0442\u0440\u0430\u0442. Net \u0441\u0432\u0435\u0440\u0445\u0443.",
  "flowPage.periodAria": "\u041f\u0435\u0440\u0438\u043e\u0434 \u043f\u043e\u0442\u043e\u043a\u0430",
  "flowPage.col.in": "\u0412\u0445\u043e\u0434",
  "flowPage.col.out": "\u0412\u044b\u0445\u043e\u0434",
