  "flowPage.sankey.aria": "Sankey-\u0434\u0438\u0430\u0433\u0440\u0430\u043c\u043c\u0430 \u043f\u043e\u0441\u0442\u0443\u043f\u043b\u0435\u043d\u0438\u0439 \u0438 \u0440\u0430\u0441\u0445\u043e\u0434\u043e\u0432",
  "flowPage.empty.title": "\u0414\u0430\u043d\u043d\u044b\u0445 \u043f\u043e\u043a\u0430 \u043d\u0435\u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e \u0434\u043b\u044f \u0434\u0438\u0430\u0433\u0440\u0430\u043c\u043c\u044b.",
  "flowPage.empty.body": "\u041f\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u0438 \u043e\u0442\u043f\u0440\u0430\u0432\u044c\u0442\u0435 \u043f\u0435\u0440\u0435\u0432\u043e\u0434 \u2014 \u0434\u0438\u0430\u0433\u0440\u0430\u043c\u043c\u0430 \u043f\u043e\u044f\u0432\u0438\u0442\u0441\u044f, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0431\u0435 \u0441\u0442\u043e\u0440\u043e\u043d\u044b \u0441\u0442\u0430\u043d\u0443\u0442 \u043d\u0435\u043d\u0443\u043b\u0435\u0432\u044b\u043c\u0438.",
  "flowPage.method.kicker": "\u041a\u0430\u043a \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f",
  "flowPage.method.body": "\u0412\u0445\u043e\u0434\u044b: \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0435 30 \u0434\u043d\u0435\u0439 \u0434\u043e\u0445\u043e\u0434\u043e\u0432 \u043f\u043e banking, QRight \u0440\u043e\u044f\u043b\u0442\u0438, CyberChess \u043f\u0440\u0438\u0437\u044b, Planet \u0431\u043e\u043d\u0443\u0441\u044b. \u0412\u044b\u0445\u043e\u0434\u044b: \u0438\u0441\u0445\u043e\u0434\u044f\u0449\u0438\u0435 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u044b \u043f\u043e \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u044f\u043c Subscriptions / Tips / Contacts / Other. \u0422\u043e\u043b\u0449\u0438\u043d\u0430 \u043b\u0435\u043d\u0442\u044b \u221d (\u0434\u043e\u043b\u044f \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u0430 \u00d7 \u0434\u043e\u043b\u044f \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0438); \u043f\u0440\u044f\u043c\u0430\u044f source\u2192category \u0442\u0440\u0430\u0441\u0441\u0438\u0440\u043e\u0432\u043a\u0430 \u0435\u0449\u0451 \u043d\u0435 \u0442\u0440\u0435\u043a\u0430\u0435\u0442\u0441\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0432\u0438\u0437\u0443\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u044f \u043f\u043e \u0431\u0430\u043b\u0430\u043d\u0441\u0443 \u043c\u0430\u0441\u0441, \u0430 \u043d\u0435 \u043f\u043e \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u0430\u043c.",
  "flowPage.cta.kicker": "\u0414\u0440\u0443\u0433\u0438\u0435 \u0441\u0440\u0435\u0437\u044b",
