  "tour.btn.back": "\u041d\u0430\u0437\u0430\u0434",
  "tour.btn.next": "\u041f\u043e\u043a\u0430\u0437\u0430\u0442\u044c \u2192 \u0414\u0430\u043b\u044c\u0448\u0435",
  "tour.btn.finish": "\u041f\u043e\u043a\u0430\u0437\u0430\u0442\u044c \u0438 \u0437\u0430\u0432\u0435\u0440\u0448\u0438\u0442\u044c",
  "tour.step.wallet.label": "\u041a\u043e\u0448\u0435\u043b\u0451\u043a",
  "tour.step.wallet.headline": "\u0417\u0434\u0435\u0441\u044c \u0436\u0438\u0432\u0451\u0442 \u0432\u0430\u0448 AEC-\u043a\u043e\u0448\u0435\u043b\u0451\u043a",
  "tour.step.wallet.body":
    "\u041f\u043e\u043f\u043e\u043b\u043d\u044f\u0439\u0442\u0435, \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u043d\u0430 \u043b\u044e\u0431\u043e\u0439 \u0441\u0447\u0451\u0442 \u0438 \u043d\u0430\u0431\u043b\u044e\u0434\u0430\u0439\u0442\u0435, \u043a\u0430\u043a \u0431\u0430\u043b\u0430\u043d\u0441 \u0440\u0430\u0441\u0442\u0451\u0442 \u0441 \u0436\u0438\u0432\u044b\u043c \u0433\u0440\u0430\u0444\u0438\u043a\u043e\u043c \u0438 \u0430\u043d\u0438\u043c\u0430\u0446\u0438\u0435\u0439 CoinTower. \u041c\u0435\u043d\u044f\u0439\u0442\u0435 \u0432\u0430\u043b\u044e\u0442\u0443 \u043e\u0442\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u044f \u043a\u043e\u0433\u0434\u0430 \u0443\u0433\u043e\u0434\u043d\u043e \u2014 \u043a\u043e\u043d\u0432\u0435\u0440\u0442\u0430\u0446\u0438\u044f \u043f\u0440\u0438\u043c\u0435\u043d\u0438\u0442\u0441\u044f \u0432\u0435\u0437\u0434\u0435.",
  "tour.step.wallet.tip":
    "\u041f\u043e\u043f\u0440\u043e\u0431\u0443\u0439\u0442\u0435 \u0441\u043f\u0435\u0440\u0432\u0430 \u043f\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u044c \u043d\u0430 500 AEC \u2014 \u0443\u0432\u0438\u0434\u0438\u0442\u0435, \u043a\u0430\u043a \u0431\u0430\u043b\u0430\u043d\u0441 \u0430\u043d\u0438\u043c\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0438 \u043e\u0431\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u043a\u0430 \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u044b.",
  "tour.step.ecosystem.label": "\u0421\u0435\u0433\u043e\u0434\u043d\u044f \u043f\u043e AEVION",
  "tour.step.ecosystem.headline": "\u041e\u0434\u0438\u043d \u043f\u0443\u043b\u044c\u0441, \u0447\u0435\u0442\u044b\u0440\u0435 \u043c\u043e\u0434\u0443\u043b\u044f",
  "tour.step.ecosystem.body":
    "\u041a\u0430\u0436\u0434\u0430\u044f \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0430 QRight, \u0442\u0443\u0440\u043d\u0438\u0440 CyberChess, \u0431\u043e\u043d\u0443\u0441 Planet \u0438 \u0431\u0430\u043d\u043a\u043e\u0432\u0441\u043a\u0430\u044f \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f \u0432\u043b\u0438\u0432\u0430\u044e\u0442\u0441\u044f \u0432 \u044d\u0442\u0443 \u0441\u0442\u0440\u043e\u043a\u0443. \u041d\u0430\u0436\u043c\u0438\u0442\u0435 \u043b\u044e\u0431\u0443\u044e \u043f\u043b\u0438\u0442\u043a\u0443, \u0447\u0442\u043e\u0431\u044b \u043f\u0440\u044b\u0433\u043d\u0443\u0442\u044c \u0432 \u043c\u043e\u0434\u0443\u043b\u044c \u2014 \u0438\u0441\u0442\u043e\u0440\u0438\u044f \u0432\u0430\u0448\u0438\u0445 \u0434\u0435\u043d\u0435\u0433 \u0438 \u0435\u0441\u0442\u044c \u0438\u0441\u0442\u043e\u0440\u0438\u044f \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u044b.",
  "tour.step.forecast.label": "\u0424\u0438\u043d\u0430\u043d\u0441\u043e\u0432\u044b\u0439 \u043f\u0440\u043e\u0433\u043d\u043e\u0437",
  "tour.step.forecast.headline": "\u041a\u0443\u0434\u0430 \u0434\u0432\u0438\u0436\u0443\u0442\u0441\u044f \u0432\u0430\u0448\u0438 \u0434\u0435\u043d\u044c\u0433\u0438",
  "tour.step.forecast.body":
    "\u0422\u0440\u0438 \u0441\u0446\u0435\u043d\u0430\u0440\u0438\u044f \u00d7 \u0442\u0440\u0438 \u0433\u043e\u0440\u0438\u0437\u043e\u043d\u0442\u0430 \u043f\u043b\u044e\u0441 \u0442\u043e\u0447\u043d\u044b\u0435 \u0434\u0430\u0442\u044b \u0434\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f \u043a\u0430\u0436\u0434\u043e\u0439 \u0446\u0435\u043b\u0438 \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u0439. \u041f\u0440\u043e\u0433\u043d\u043e\u0437 \u0443\u0447\u0438\u0442\u044b\u0432\u0430\u0435\u0442 \u0432\u0430\u0448 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0439 \u0442\u0435\u043c\u043f \u0437\u0430\u0440\u0430\u0431\u043e\u0442\u043a\u0430 \u0437\u0430 30 \u0434\u043d\u0435\u0439 \u043f\u043e \u0432\u0441\u0435\u043c \u043c\u043e\u0434\u0443\u043b\u044f\u043c.",
  "tour.step.forecast.tip":
    "\u041f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0438\u0442\u0435 \u0441\u0446\u0435\u043d\u0430\u0440\u0438\u0439 \u043d\u0430 \u00ab\u041e\u043f\u0442\u0438\u043c\u0438\u0441\u0442\u0438\u0447\u043d\u044b\u0439\u00bb, \u0447\u0442\u043e\u0431\u044b \u0443\u0432\u0438\u0434\u0435\u0442\u044c \u0433\u043e\u0434\u043e\u0432\u043e\u0435 \u0441\u043b\u043e\u0436\u043d\u043e\u0435 \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u0435.",
  "tour.step.trust.label": "\u0414\u043e\u0432\u0435\u0440\u0438\u0435 \u0438 \u043f\u0438\u0440\u044b",
  "tour.step.trust.headline": "\u0412\u0430\u0448\u0430 \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u044f \u0432\u043e \u0432\u0441\u0435\u0439 AEVION",
  "tour.step.trust.body":
    "Ecosystem Trust Score \u0432\u043b\u0438\u044f\u0435\u0442 \u043d\u0430 \u043b\u0438\u043c\u0438\u0442\u044b \u0437\u0430\u0440\u043f\u043b\u0430\u0442\u043d\u044b\u0445 \u0430\u0432\u0430\u043d\u0441\u043e\u0432 \u0438 \u043c\u0435\u0441\u0442\u043e \u0432 \u0440\u0435\u0439\u0442\u0438\u043d\u0433\u0435. \u00ab\u0421\u0430\u043c\u044b\u0435 \u0431\u044b\u0441\u0442\u0440\u044b\u0435 \u043f\u043e\u0431\u0435\u0434\u044b\u00bb \u043f\u043e\u0434\u0441\u043a\u0430\u0436\u0443\u0442, \u043a\u0430\u043a\u0438\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u044e\u0442 \u0432\u0430\u0448 \u0431\u0430\u043b\u043b.",
  "tour.step.trust.tip":
    "\u0427\u0442\u043e\u0431\u044b \u043e\u0442\u043a\u0440\u044b\u0442\u044c \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u044b\u0435 \u0430\u0432\u0430\u043d\u0441\u044b, \u043d\u0443\u0436\u0435\u043d \u0431\u0430\u043b\u043b \u0443\u0440\u043e\u0432\u043d\u044f Growing (20+).",
  "tour.step.achievements.label": "\u0414\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f",
  "tour.step.achievements.headline": "18 \u0437\u043d\u0430\u0447\u043a\u043e\u0432, 4 \u0442\u0440\u0435\u043a\u0430",
  "tour.step.achievements.body":
    "\u041a\u0430\u0436\u0434\u043e\u0435 \u0432\u0430\u0448\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u0437\u043d\u0430\u0447\u043a\u0438 \u0432 \u0442\u0440\u0435\u043a\u0430\u0445 Banking / Creator / Ecosystem / Security. \u0417\u0430\u043a\u0440\u044b\u0442\u044b\u0435 \u0437\u043d\u0430\u0447\u043a\u0438 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0432\u044b \u0431\u043b\u0438\u0437\u043a\u0438 \u043a \u0446\u0435\u043b\u0438.",
  "tour.step.achievements.tip":
    "\u0412\u043a\u043b\u044e\u0447\u0438\u0442\u0435 \u0431\u0438\u043e\u043c\u0435\u0442\u0440\u0438\u044e, \u043f\u043e\u0434\u043f\u0438\u0448\u0438\u0442\u0435 \u043e\u0434\u0438\u043d \u043f\u0435\u0440\u0435\u0432\u043e\u0434 \u0438 \u0437\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u0443\u0439\u0442\u0435 \u0440\u0430\u0431\u043e\u0442\u0443 \u0432 QRight \u2014 \u0442\u0440\u0438 \u043f\u0435\u0440\u0432\u044b\u0445 \u0437\u043d\u0430\u0447\u043a\u0430 \u0431\u0443\u0434\u0443\u0442 \u0432\u0430\u0448\u0438 \u0441\u0440\u0430\u0437\u0443.",

