  "copilot.ap.set.timelockGuard.hint": "\u0411\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0438\u0441\u0445\u043e\u0434\u044f\u0449\u0438\u0435, \u0435\u0441\u043b\u0438 \u0431\u0430\u043b\u0430\u043d\u0441 \u0443\u043f\u0430\u0434\u0451\u0442 \u043d\u0438\u0436\u0435 \u0441\u0443\u043c\u043c\u044b \u043f\u043e\u0434\u0430\u0440\u043a\u043e\u0432, \u0440\u0430\u0437\u0431\u043b\u043e\u043a\u0438\u0440\u0443\u044e\u0449\u0438\u0445\u0441\u044f \u0432 \u0431\u043b\u0438\u0436\u0430\u0439\u0448\u0438\u0435 {hours}\u0447",
