  "copilot.ins.idle.body": "\u0420\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u0430\u044f \u0437\u0430\u0440\u043f\u043b\u0430\u0442\u0430 \u0438\u043b\u0438 \u0441\u0431\u0435\u0440\u043f\u0435\u0440\u0435\u0432\u043e\u0434 \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044e\u0442 Trust Score \u0438 \u0434\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f.",
  "copilot.ins.idle.cta": "\u041d\u0430\u0441\u0442\u0440\u043e\u0438\u0442\u044c",
