  "copilot.ins.network.title": "\u0423 \u0432\u0430\u0441 \u0435\u0449\u0451 \u043d\u0435\u0442 \u041a\u0440\u0443\u0433\u043e\u0432",
  "copilot.ins.network.body": "\u0421\u043e\u0437\u0434\u0430\u0439\u0442\u0435 \u043e\u0431\u0449\u0443\u044e \u0433\u0440\u0443\u043f\u043f\u0443, \u0447\u0442\u043e\u0431\u044b \u0434\u0435\u043b\u0438\u0442\u044c \u0441\u0447\u0451\u0442, \u0434\u0430\u0440\u0438\u0442\u044c \u0438\u043b\u0438 \u0437\u0430\u043f\u0440\u0430\u0448\u0438\u0432\u0430\u0442\u044c \u043e\u043f\u043b\u0430\u0442\u0443.",
