  "copilot.sim.preview.would": "\u041f\u0440\u0435\u0432\u044c\u044e \u00b7 \u0441\u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442",
  "copilot.sim.preview.skip": "\u041f\u0440\u0435\u0432\u044c\u044e \u00b7 \u043f\u0440\u043e\u043f\u0443\u0441\u0442\u0438\u0442",
  "copilot.sim.tick.label": "\u0422\u0438\u043a: ",
  "copilot.sim.tick.skip": "\u043f\u0440\u043e\u043f\u0443\u0441\u043a \u00b7 {reason}",
  "copilot.sim.watchdog.label": "\u0421\u0442\u043e\u0440\u043e\u0436: ",
  "copilot.sim.watchdog.freeze": "\ud83d\udd12 \u0437\u0430\u043c\u043e\u0440\u043e\u0437\u043a\u0430 \u00b7 \u0432\u0441\u043f\u043b\u0435\u0441\u043a {count} \u00b7 {value} AEC",
  "copilot.sim.watchdog.idle": "\u043e\u0436\u0438\u0434\u0430\u043d\u0438\u0435 \u00b7 {reason}",
  "copilot.sim.note": "\u0422\u043e\u043b\u044c\u043a\u043e \u0441\u0438\u043c\u0443\u043b\u044f\u0446\u0438\u044f \u2014 \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u043e. \u0420\u0435\u0430\u043b\u044c\u043d\u044b\u0439 \u0442\u0438\u043a \u043a\u0430\u0436\u0434\u044b\u0435 60\u0441; \u0441\u0442\u043e\u0440\u043e\u0436 \u043a\u0430\u0436\u0434\u044b\u0435 15\u0441.",

  // Metric tooltips
  "tip.balance": "\u0421\u043a\u043e\u043b\u044c\u043a\u043e AEC \u0441\u0435\u0439\u0447\u0430\u0441 \u043d\u0430 \u0432\u0430\u0448\u0435\u043c \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0435. AEC \u2014 \u0435\u0434\u0438\u043d\u0438\u0446\u0430 \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u044b AEVION \u0434\u043b\u044f P2P-\u043f\u0435\u0440\u0435\u0432\u043e\u0434\u043e\u0432, \u0440\u043e\u044f\u043b\u0442\u0438 \u0438 \u043f\u0440\u0438\u0437\u043e\u0432\u044b\u0445.",
  "tip.netflow": "\u0421\u0443\u043c\u043c\u0430 \u0432\u0445\u043e\u0434\u044f\u0449\u0438\u0445 \u043c\u0438\u043d\u0443\u0441 \u0438\u0441\u0445\u043e\u0434\u044f\u0449\u0438\u0445 AEC \u0437\u0430 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0435 30 \u0434\u043d\u0435\u0439. \u0417\u0435\u043b\u0451\u043d\u044b\u0439 = \u0437\u0430\u0440\u0430\u0431\u043e\u0442\u0430\u043b\u0438 \u0431\u043e\u043b\u044c\u0448\u0435, \u0447\u0435\u043c \u043f\u043e\u0442\u0440\u0430\u0442\u0438\u043b\u0438.",
  "tip.ops": "\u041a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u0439 \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0430 (\u043f\u043e\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u044f + \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u044b) \u0437\u0430 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0435 30 \u0434\u043d\u0435\u0439.",
  "tip.lastActivity": "\u0412\u0440\u0435\u043c\u044f \u0441 \u043c\u043e\u043c\u0435\u043d\u0442\u0430 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0435\u0433\u043e \u0441\u043e\u0431\u044b\u0442\u0438\u044f \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u0430.",
  "tip.trustScore": "\u0421\u0432\u043e\u0434\u043d\u0430\u044f \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u044f 0\u2013100. \u041e\u0431\u044a\u0435\u0434\u0438\u043d\u044f\u0435\u0442 8 \u0444\u0430\u043a\u0442\u043e\u0440\u043e\u0432: \u0431\u0430\u043d\u043a\u0438\u043d\u0433, \u0440\u043e\u044f\u043b\u0442\u0438, \u0448\u0430\u0445\u043c\u0430\u0442\u044b, Planet, \u0430\u0443\u0434\u0438\u0442 \u043f\u043e\u0434\u043f\u0438\u0441\u0435\u0439, \u0431\u0438\u043e\u043c\u0435\u0442\u0440\u0438\u044f, \u0434\u043e\u0441\u0442\u0438\u0436\u0435\u043d\u0438\u044f, \u0441\u0435\u0442\u044c. \u0412\u044b\u0448\u0435 \u0431\u0430\u043b\u043b \u2014 \u0431\u043e\u043b\u044c\u0448\u0435 \u043b\u0438\u043c\u0438\u0442 \u0430\u0432\u0430\u043d\u0441\u0430 \u0438 \u043f\u0440\u0438\u0432\u0438\u043b\u0435\u0433\u0438\u0439.",
  "tip.trustTier": "\u0414\u0438\u0441\u043a\u0440\u0435\u0442\u043d\u044b\u0439 \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u0438 \u2014 New / Growing / Trusted / Elite. \u041a\u0430\u0436\u0434\u044b\u0439 \u0442\u0438\u0440 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u043f\u0440\u0438\u0432\u0438\u043b\u0435\u0433\u0438\u0438 \u0432 27 \u043c\u043e\u0434\u0443\u043b\u044f\u0445 AEVION.",
  "tip.advanceLimit": "\u041c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u044b\u0439 \u0430\u0432\u0430\u043d\u0441, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0432\u044b \u043c\u043e\u0436\u0435\u0442\u0435 \u0437\u0430\u043f\u0440\u043e\u0441\u0438\u0442\u044c \u0441\u0435\u0439\u0447\u0430\u0441, \u0438\u0441\u0445\u043e\u0434\u044f \u0438\u0437 \u0432\u0430\u0448\u0435\u0433\u043e Trust-\u0442\u0438\u0440\u0430. \u0410\u0432\u0442\u043e-\u043f\u043e\u0433\u0430\u0448\u0435\u043d\u0438\u0435 \u0438\u0437 \u0432\u0445\u043e\u0434\u044f\u0449\u0438\u0445 \u0440\u043e\u044f\u043b\u0442\u0438/\u0448\u0430\u0445\u043c\u0430\u0442/Planet.",
  "tip.earningPace": "\u0421\u0440\u0435\u0434\u043d\u0438\u0439 \u0434\u043d\u0435\u0432\u043d\u043e\u0439 \u043f\u0440\u0438\u0442\u043e\u043a AEC \u0438\u0437 \u0432\u0441\u0435\u0445 \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u043e\u0432 \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u044b, \u0441\u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u043f\u043e \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u043c 30 \u0434\u043d\u044f\u043c.",
  "tip.runRate": "\u0415\u0441\u043b\u0438 \u0432\u0430\u0448 30-\u0434\u043d\u0435\u0432\u043d\u044b\u0439 \u0442\u0435\u043c\u043f \u0441\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u0441\u044f 12 \u043c\u0435\u0441\u044f\u0446\u0435\u0432 \u2014 \u0441\u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0430\u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442\u0435. \u041d\u0435 \u0433\u0430\u0440\u0430\u043d\u0442\u0438\u044f \u2014 \u0440\u044b\u043d\u043a\u0438 \u043c\u0435\u043d\u044f\u044e\u0442\u0441\u044f.",
  "tip.peerStanding": "\u0412\u0430\u0448\u0435 \u043c\u0435\u0441\u0442\u043e \u0441\u0440\u0435\u0434\u0438 ~1500 \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u0445 \u043a\u043e\u0448\u0435\u043b\u044c\u043a\u043e\u0432 AEVION \u043f\u043e 4 \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u0438\u044f\u043c. \u041d\u0430 \u043a\u0430\u043b\u0438\u0431\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u043c \u0440\u0430\u0441\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u0438\u0438; \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0439 leaderboard \u0432\u044b\u0439\u0434\u0435\u0442 \u0441 /api/ecosystem/leaderboard.",
  "tip.totalEarnings": "\u0421\u0443\u043c\u043c\u0430 \u043f\u043e 4 \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u0430\u043c \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u044b: \u0431\u0430\u043d\u043a\u043e\u0432\u0441\u043a\u0438\u0435 \u0432\u0445\u043e\u0434\u044f\u0449\u0438\u0435, QRight \u0440\u043e\u044f\u043b\u0442\u0438, \u043f\u0440\u0438\u0437\u044b CyberChess, \u0431\u043e\u043d\u0443\u0441\u044b Planet.",
  "tip.spending": "\u0418\u0441\u0445\u043e\u0434\u044f\u0449\u0438\u0435 AEC, \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0438\u0437 recurring \u0438 \u0430\u0434\u0440\u0435\u0441\u043d\u043e\u0439 \u043a\u043d\u0438\u0433\u0438. \u041f\u043e\u043b\u0435\u0437\u043d\u043e \u0434\u043b\u044f \u043c\u0435\u0441\u044f\u0447\u043d\u043e\u0433\u043e \u043e\u0431\u0437\u043e\u0440\u0430 \u0431\u044e\u0434\u0436\u0435\u0442\u0430.",
  "tip.autopilotMoved": "\u0421\u043a\u043e\u043b\u044c\u043a\u043e AEC Autopilot \u0441\u0430\u043c\u043e\u0441\u0442\u043e\u044f\u0442\u0435\u043b\u044c\u043d\u043e \u043f\u0435\u0440\u0435\u0432\u0451\u043b \u0432 \u0432\u0430\u0448\u0438 \u0446\u0435\u043b\u0438 \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u0439 \u2014 \u043f\u043e \u0441\u043e\u0433\u043b\u0430\u0441\u0438\u044e, \u0441 \u043b\u0438\u043c\u0438\u0442\u0430\u043c\u0438, \u043f\u043e\u0434 \u0430\u0443\u0434\u0438\u0442\u043e\u043c.",

