  "spending.category.subscriptions.description": "\u0418\u0441\u0445\u043e\u0434\u044f\u0449\u0438\u0435, \u0441\u043e\u0432\u043f\u0430\u0432\u0448\u0438\u0435 \u0441 \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u044b\u043c \u0440\u0430\u0441\u043f\u0438\u0441\u0430\u043d\u0438\u0435\u043c",
