  "moneyFlow.tooltip":
    "Sankey-\u0434\u0438\u0430\u0433\u0440\u0430\u043c\u043c\u0430: \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u0438 \u0434\u043e\u0445\u043e\u0434\u0430 \u0432\u0442\u0435\u043a\u0430\u044e\u0442 \u0432 \u043a\u043e\u0448\u0435\u043b\u0451\u043a \u0438 \u0432\u044b\u0442\u0435\u043a\u0430\u044e\u0442 \u043f\u043e \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u044f\u043c \u0442\u0440\u0430\u0442. \u0428\u0438\u0440\u0438\u043d\u0430 \u043b\u0435\u043d\u0442\u044b = \u0441\u0443\u043c\u043c\u0430. \u041f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0438\u0442\u0435 \u043f\u0435\u0440\u0438\u043e\u0434 \u043a\u043d\u043e\u043f\u043a\u0430\u043c\u0438 \u0432\u044b\u0448\u0435.",
