  "netWorth.tooltip":
    "\u0421\u0442\u0435\u043a-\u0434\u0438\u0430\u0433\u0440\u0430\u043c\u043c\u0430: net worth = \u0431\u0430\u043b\u0430\u043d\u0441 \u0431\u0430\u043d\u043a\u0430 (\u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d \u0438\u0437 \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u0439) + \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u043d\u044b\u0439 \u044d\u043a\u043e\u0441\u0438\u0441\u0442\u0435\u043c\u043d\u044b\u0439 \u0434\u043e\u0445\u043e\u0434 (qright + chess + planet) + \u043b\u0438\u043d\u0435\u0439\u043d\u0430\u044f \u043e\u0446\u0435\u043d\u043a\u0430 \u0441\u0442\u043e\u0438\u043c\u043e\u0441\u0442\u0438 \u0446\u0435\u043b\u0435\u0439. \u0422\u043e\u0447\u043a\u0430-\u043c\u0430\u0440\u043a\u0435\u0440 \u2014 \u0438\u0441\u0442\u043e\u0440\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0432\u0435\u0440\u0448\u0438\u043d\u0430 \u0432 \u043e\u043a\u043d\u0435.",
