  "subScan.tooltip":
    "\u042d\u0432\u0440\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0441\u043a\u0430\u043d \u0432\u0430\u0448\u0438\u0445 recurring. \u0423\u0441\u0442\u0430\u0440\u0435\u0432\u0448\u0438\u0439 = \u043d\u0435\u0442 \u0437\u0430\u043f\u0443\u0441\u043a\u0430 \u226560 \u0434\u043d\u0435\u0439. \u0414\u043e\u0440\u043e\u0433\u043e\u0439 = \u043c\u0435\u0441\u044f\u0447\u043d\u044b\u0439 \u044d\u043a\u0432\u0438\u0432\u0430\u043b\u0435\u043d\u0442 \u22652\u00d7 \u043c\u0435\u0434\u0438\u0430\u043d\u044b \u043f\u043e \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u043c. \u0414\u0443\u0431\u043b\u044c = \u0441\u043e\u0432\u043f\u0430\u0434\u0430\u0435\u0442 \u043f\u043e\u043b\u0443\u0447\u0430\u0442\u0435\u043b\u044c + \u043f\u0435\u0440\u0438\u043e\u0434 + \u0441\u0443\u043c\u043c\u0430 \u0441 \u0434\u0440\u0443\u0433\u043e\u0439 \u0437\u0430\u043f\u0438\u0441\u044c\u044e. \u041f\u0430\u0443\u0437\u0430 / \u0423\u0434\u0430\u043b\u0438\u0442\u044c \u2014 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u043e.",
