  "sugg.tooltip":
    "\u042d\u0432\u0440\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0441\u043e\u0432\u0435\u0442\u044b \u043f\u043e \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f\u043c, \u0431\u0430\u043b\u0430\u043d\u0441\u0443, Trust Score, \u043b\u0438\u043c\u0438\u0442\u0430\u043c, recurring, \u0446\u0435\u043b\u044f\u043c \u0438 Vault. \u0411\u0435\u0437 \u0431\u044d\u043a\u0435\u043d\u0434\u0430 \u0438 \u0430\u043d\u0430\u043b\u0438\u0442\u0438\u043a\u0438 \u2014 \u0447\u0438\u0442\u0430\u044e\u0442 \u0432\u0436\u0438\u0432\u0443\u044e \u0442\u0435 \u0436\u0435 \u0434\u0430\u043d\u043d\u044b\u0435, \u0447\u0442\u043e \u0438 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0439 /bank.",
