  "sugg.idle.body":
    "{balance} AEC \u043b\u0435\u0436\u0438\u0442 \u0431\u0435\u0437 \u0434\u0435\u043b\u0430. Vault \u043d\u0430 90 \u0434\u043d \u043f\u043e\u0434 5% APY \u0431\u0443\u0434\u0435\u0442 \u043d\u0430\u0447\u0438\u0441\u043b\u044f\u0442\u044c \u0441\u0438\u043c\u0443\u043b\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0434\u043e\u0445\u043e\u0434.",
  "sugg.subDrag.title": "\u041f\u043e\u0434\u043f\u0438\u0441\u043a\u0438 \u0441\u044a\u0435\u0434\u0430\u044e\u0442 \u0440\u0430\u0441\u0445\u043e\u0434",
  "sugg.subDrag.body":
    "{pct}% \u0440\u0430\u0441\u0445\u043e\u0434\u0430 \u0437\u0430 30 \u0434\u043d\u0435\u0439 \u0443\u0448\u043b\u0438 \u043d\u0430 recurring. Scanner \u043d\u0430\u0439\u0434\u0451\u0442 \u0434\u0443\u0431\u043b\u0438 \u0438 \u0443\u0441\u0442\u0430\u0440\u0435\u0432\u0448\u0438\u0435 \u0437\u0430\u043f\u0438\u0441\u0438.",
  "sugg.trust.title": "\u041e\u0434\u0438\u043d \u0448\u0430\u0433 \u0434\u043e \u0442\u0438\u0440\u0430 {tier}",
