  "forecastPage.headline": "\u04ae\u0448 \u0441\u0446\u0435\u043d\u0430\u0440\u0438\u0439. \u04ae\u0448 \u043a\u04e9\u043a\u0436\u0438\u0435\u043a.",
  "forecastPage.lede": "30 / 90 / 365 \u043a\u04af\u043d\u0434\u0456\u043a \u043a\u04e9\u043a\u0436\u0438\u0435\u043a\u0442\u0435 \u043a\u043e\u043d\u0441\u0435\u0440\u0432\u0430\u0442\u0438\u0432\u0442\u0456, \u0448\u044b\u043d\u0430\u0439\u044b \u0436\u04d9\u043d\u0435 \u043e\u043f\u0442\u0438\u043c\u0438\u0441\u0442\u0456\u043a \u0431\u043e\u043b\u0436\u0430\u043c\u0434\u0430\u0440. \u041c\u0430\u049b\u0441\u0430\u0442 ETA-\u0441\u044b \u0431\u0435\u043b\u0441\u0435\u043d\u0434\u0456 \u043a\u0456\u0440\u0456\u0441 \u0430\u0493\u044b\u043d\u0434\u0430\u0440\u044b\u04a3\u044b\u0437\u0434\u0430\u043d \u0435\u0441\u0435\u043f\u0442\u0435\u043b\u0435\u0434\u0456 \u2014 royalty, \u044d\u043a\u043e\u0436\u04af\u0439\u0435 \u0436\u04d9\u043d\u0435 \u0448\u0430\u0445\u043c\u0430\u0442.",
  "forecastPage.empty.title": "\u04d8\u043c\u0438\u044f\u043d \u04d9\u043b\u0456 \u0436\u043e\u049b",
  "forecastPage.empty.body": "\u0411\u043e\u043b\u0436\u0430\u043c\u0493\u0430 \u0448\u043e\u0442 \u043a\u0435\u0440\u0435\u043a. \u04d8\u043c\u0438\u044f\u043d\u0434\u044b \u0430\u0448\u044b\u04a3\u044b\u0437, \u0442\u0456\u0440\u043a\u0435\u043b\u0456\u04a3\u0456\u0437 \u2014 \u0431\u043e\u043b\u0436\u0430\u043c \u043e\u0441\u044b\u043d\u0434\u0430 \u043f\u0430\u0439\u0434\u0430 \u0431\u043e\u043b\u0430\u0434\u044b.",
  "forecastPage.method.kicker": "\u04d8\u0434\u0456\u0441\u0442\u0435\u043c\u0435",
  "forecastPage.method.body": "\u04d8\u0440 \u0441\u0446\u0435\u043d\u0430\u0440\u0438\u0439 \u04af\u0448 \u043a\u0456\u0440\u0456\u0441 \u0430\u0493\u044b\u043d\u044b\u043d\u0430\u043d \u0430\u0493\u044b\u043c\u0434\u0430\u0493\u044b \u0430\u0439\u043b\u044b\u049b \u043a\u0456\u0440\u0456\u0441\u043a\u0435 \u0442\u04b1\u0440\u0430\u049b\u0442\u044b \u043a\u043e\u044d\u0444\u0444\u0438\u0446\u0438\u0435\u043d\u0442 \u049b\u043e\u043b\u0434\u0430\u043d\u0430\u0434\u044b. ETA \u0431\u043e\u043b\u0436\u0430\u043d\u0430\u0442\u044b\u043d \u0431\u0430\u043b\u0430\u043d\u0441\u0442\u044b \u04d9\u0440 \u043c\u0430\u049b\u0441\u0430\u0442\u049b\u0430 \u0434\u0435\u0439\u0456\u043d \u0438\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044f\u043b\u0430\u0443 \u0430\u0440\u049b\u044b\u043b\u044b \u0435\u0441\u0435\u043f\u0442\u0435\u043b\u0435\u0434\u0456. \u0421\u0430\u043d\u0434\u0430\u0440 \u043a\u04e9\u0440\u043d\u0435\u043a\u0456 \u2014 \u049b\u0430\u0437\u0456\u0440\u0433\u0456 \u043c\u0456\u043d\u0435\u0437-\u049b\u04b1\u043b\u044b\u049b \u04e9\u0437\u0433\u0435\u0440\u043c\u0435\u0439\u0434\u0456 \u0434\u0435\u043f \u049b\u0430\u0431\u044b\u043b\u0434\u0430\u043d\u0430\u0434\u044b.",
  "forecastPage.cta.kicker": "\u0421\u043e\u043d\u0434\u0430\u0439-\u0430\u049b \u043f\u0430\u0439\u0434\u0430\u043b\u044b",
