  "about.lede": "AEVION Bank \u2014 creator-first \u044d\u043a\u043e\u0436\u04af\u0439\u0435\u043d\u0456\u04a3 \u044d\u043a\u043e\u043d\u043e\u043c\u0438\u043a\u0430\u043b\u044b\u049b \u0442\u0430\u043c\u044b\u0440\u044b. \u0410\u049b\u0448\u0430 \u0441\u0456\u0437 \u0436\u0430\u0441\u0430\u0493\u0430\u043d \u043d\u04d9\u0440\u0441\u0435\u043c\u0435\u043d \u049b\u043e\u0441\u044b\u043b\u0430\u0434\u044b: \u0440\u043e\u044f\u043b\u0442\u0438 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0442\u044b \u0442\u04af\u0441\u0435\u0434\u0456, \u043a\u0440\u0435\u0434\u0438\u0442 \u0431\u0435\u0434\u0435\u043b\u0456\u04a3\u0456\u0437\u0431\u0435\u043d \u0431\u0456\u0440\u0433\u0435 \u04e9\u0441\u0435\u0434\u0456, \u04d9\u0440 \u04d9\u043b\u0435\u0443\u043c\u0435\u0442\u0442\u0456\u043a \u0441\u04d9\u0442 \u049b\u04b1\u043d\u0434\u044b \u0442\u0430\u0441\u0443\u044b \u043c\u04af\u043c\u043a\u0456\u043d.",
  "about.s1.kicker": "\u041a\u043e\u043c\u043f\u043e\u0437\u0438\u0446\u0438\u044f",
  "about.s1.title": "\u0428\u044b\u0493\u0430\u0440\u043c\u0430\u0448\u044b\u043b\u044b\u049b \u0431\u043e\u043b\u0430\u0442\u044b\u043d \u0436\u0435\u0440\u0434\u0435 \u0430\u049b\u0448\u0430",
  "about.s1.body": "QRight IP-\u04a3\u0456\u0437\u0434\u0456 \u0440\u0430\u0441\u0442\u0430\u0439\u0434\u044b \u0436\u04d9\u043d\u0435 \u0440\u043e\u044f\u043b\u0442\u0438\u0434\u0456 \u04d9\u043c\u0438\u044f\u043d\u0493\u0430 \u0431\u0456\u0440 \u043a\u043b\u0438\u043a \u0436\u0430\u0441\u0430\u043c\u0430\u0441\u0442\u0430\u043d \u049b\u04b1\u044f\u0434\u044b. CyberChess \u0436\u04af\u043b\u0434\u0435 \u049b\u043e\u0440\u044b \u0431\u0430\u043b\u0430\u043d\u0441\u049b\u0430 \u0442\u04af\u0441\u0435\u0434\u0456. Planet \u043a\u0443\u04d9\u043b\u0456\u043a\u0442\u0435\u0440\u0456 Trust Score-\u0433\u0435 \u049b\u043e\u0441\u044b\u043b\u0430\u0434\u044b. Bank \u2014 \u0436\u0435\u043a\u0435 \u049b\u043e\u0441\u044b\u043c\u0448\u0430 \u0435\u043c\u0435\u0441, \u0431\u0430\u0440\u043b\u044b\u0493\u044b\u043d \u043c\u0430\u0493\u044b\u043d\u0430\u043b\u044b \u0435\u0442\u0435\u0442\u0456\u043d \u049b\u0430\u0431\u0430\u0442.",
  "about.s2.kicker": "Trust > \u043a\u0435\u043f\u0456\u043b",
  "about.s2.title": "\u041a\u0440\u0435\u0434\u0438\u0442 \u0431\u0435\u0434\u0435\u043b\u0433\u0435, \u049b\u0430\u0493\u0430\u0437\u0493\u0430 \u0435\u043c\u0435\u0441",
  "about.s2.body": "\u0416\u0430\u043b\u0430\u049b\u044b \u0430\u0432\u0430\u043d\u0441 Trust Score \u04e9\u0441\u0443\u0456\u043c\u0435\u043d \u0430\u0448\u044b\u043b\u0430\u0434\u044b \u2014 \u0442\u0456\u0440\u043a\u0435\u0443\u043b\u0435\u0440, \u049b\u043e\u043b \u049b\u043e\u044e\u043b\u0430\u0440, \u04e9\u0442\u0435\u043b\u0433\u0435\u043d \u043c\u0456\u043d\u0434\u0435\u0442\u0442\u0435\u043c\u0435\u043b\u0435\u0440 \u043c\u0435\u043d \u044d\u043a\u043e\u0436\u04af\u0439\u0435 \u0431\u0435\u043b\u0441\u0435\u043d\u0434\u0456\u043b\u0456\u0433\u0456\u043d\u0435\u043d. Trusted-\u043a\u0435 500 AEC, Elite-\u043a\u0435 2000. KYC \u0442\u0435\u0430\u0442\u0440\u0456 \u0436\u043e\u049b.",
  "about.s3.kicker": "\u04d8\u043b\u0435\u0443\u043c\u0435\u0442\u0442\u0456\u043a",
  "about.s3.title": "\u041a\u0435\u0437 \u043a\u0435\u043b\u0433\u0435\u043d \u0431\u0430\u0439\u043b\u0430\u043d\u044b\u0441 \u0430\u049b\u0448\u0430 \u0442\u0430\u0441\u0443\u044b \u043c\u04af\u043c\u043a\u0456\u043d",
  "about.s3.body": "\u0428\u043e\u0442\u0442\u044b \u04af\u0448 \u0442\u0438\u044e\u043c\u0435\u043d \u0431\u04e9\u043b\u0456\u04a3\u0456\u0437. \u0425\u0430\u0431\u0430\u0440\u043b\u0430\u043c\u0430\u043c\u0435\u043d \u0442\u0430\u049b\u044b\u0440\u044b\u043f\u0442\u044b\u049b \u0441\u044b\u0439\u043b\u044b\u049b \u0436\u0456\u0431\u0435\u0440\u0456\u04a3\u0456\u0437. \u0422\u043e\u043f\u0442\u044b\u049b circle-\u0433\u0435 payment request \u049b\u043e\u0439\u044b\u04a3\u044b\u0437. \u0411\u0430\u043b\u0430\u043d\u0441 \u0442\u04af\u0441\u043a\u0435\u043d\u0434\u0435 \u04e9\u0437\u0456 \u0442\u043e\u049b\u0442\u0430\u0439\u0442\u044b\u043d \u0442\u04b1\u0440\u0430\u049b\u0442\u044b \u0430\u0443\u0434\u0430\u0440\u044b\u043c \u0436\u043e\u0441\u043f\u0430\u0440\u043b\u0430\u04a3\u044b\u0437.",
  "about.s4.kicker": "\u0422\u04d9\u0443\u0435\u043b\u0441\u0456\u0437\u0434\u0456\u043a",
  "about.s4.title": "\u0414\u0435\u0440\u0435\u043a\u0442\u0435\u0440\u0456\u04a3\u0456\u0437, \u049b\u04b1\u0440\u044b\u043b\u0493\u044b\u04a3\u044b\u0437, \u0441\u0456\u0437\u0434\u0456\u04a3 \u0442\u0430\u04a3\u0434\u0430\u0443\u044b\u04a3\u044b\u0437",
  "about.s4.body": "\u0428\u0435\u043a\u0442\u0435\u043d \u0436\u043e\u0493\u0430\u0440\u044b \u0430\u0443\u0434\u0430\u0440\u044b\u043c\u0434\u0430\u0440\u0493\u0430 \u0431\u0438\u043e\u043c\u0435\u0442\u0440\u0438\u044f. QSign \u04d9\u0440 \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f\u0493\u0430 Ed25519 \u043a\u0456\u043b\u0442\u0456\u043c\u0435\u043d \u049b\u043e\u043b \u049b\u043e\u044f\u0434\u044b. Activity timeline \u0430\u043d\u043e\u043c\u0430\u043b\u0438\u044f\u043b\u0430\u0440\u0434\u044b \u0430\u043b\u0434\u044b\u043d \u0430\u043b\u0430 \u043a\u04e9\u0440\u0441\u0435\u0442\u0435\u0434\u0456. \u0411\u04af\u043a\u0456\u043b \u04d9\u043c\u0438\u044f\u043d\u0434\u044b JSON \u0435\u0442\u0456\u043f \u044d\u043a\u0441\u043f\u043e\u0440\u0442\u0442\u0430\u04a3\u044b\u0437 \u2014 vendor lock-in \u0436\u043e\u049b.",
  "about.cta.kicker": "Live MVP",
  "about.cta.title": "\u0411\u04b1\u043b \u0431\u04af\u0433\u0456\u043d \u0436\u04b1\u043c\u044b\u0441 \u0456\u0441\u0442\u0435\u0439\u0434\u0456.",
  "about.cta.body": "12 \u0442\u0456\u0440\u0456 \u043c\u043e\u0434\u0443\u043b\u044c. 18 \u0431\u0430\u043d\u043a \u0444\u0443\u043d\u043a\u0446\u0438\u044f\u0441\u044b. 11 \u0456\u0448\u043a\u0456 \u043c\u0430\u0440\u0448\u0440\u0443\u0442. EN / RU / KZ. PWA \u0440\u0435\u0442\u0456\u043d\u0434\u0435 \u043e\u0440\u043d\u0430\u0442\u044b\u043b\u0430\u0434\u044b. \u0421\u0435\u043d\u0456\u043c \u0433\u0440\u0430\u0444\u044b \u0442\u0456\u0440\u0456.",
