  // Card /bank/card
  "card.kicker": "\u04d8\u043c\u0438\u044f\u043d \u043a\u0430\u0440\u0442\u0430\u0441\u044b",
  "card.headline": "\u0411\u0435\u0434\u0435\u043b\u0433\u0435 \u043d\u0435\u0433\u0456\u0437\u0434\u0435\u043b\u0433\u0435\u043d \u043a\u0430\u0440\u0442\u0430.",
  "card.lede": "AEVION Bank \u043a\u0430\u0440\u0442\u0430\u0441\u044b \u2014 \u0432\u0438\u0440\u0442\u0443\u0430\u043b\u0434\u044b \u0430\u0440\u0442\u0435\u0444\u0430\u043a\u0442: \u0431\u0456\u0440 \u043a\u04e9\u0437\u049b\u0430\u0440\u0430\u0441\u043f\u0435\u043d \u04d9\u043c\u0438\u044f\u043d \u043a\u0435\u0439\u043f\u0456\u043d \u043a\u04e9\u0440\u0435\u0441\u0456\u0437 \u0436\u04d9\u043d\u0435 \u0431\u04e9\u043b\u0456\u0441\u0435 \u0430\u043b\u0430\u0441\u044b\u0437. \u0414\u0435\u04a3\u0433\u0435\u0439 \u2014 Trust Score; \u0433\u043e\u043b\u043e\u0433\u0440\u0430\u0444\u0438\u044f\u043b\u044b\u049b \u0444\u043e\u043b\u044c\u0433\u0430 \u043e\u043d\u044b \u0431\u04e9\u043b\u0456\u043f \u043a\u04e9\u0440\u0441\u0435\u0442\u0435\u0434\u0456. \u041f\u043b\u0430\u0441\u0442\u0438\u043a\u0441\u0456\u0437, \u0436\u0435\u0442\u043a\u0456\u0437\u0443\u0441\u0456\u0437.",
  "card.flipAria": "\u041a\u0430\u0440\u0442\u0430\u043d\u044b\u04a3 \u0430\u0440\u0442\u049b\u044b \u0436\u0430\u0493\u044b\u043d \u043a\u04e9\u0440\u0443 \u04af\u0448\u0456\u043d \u0430\u0439\u043d\u0430\u043b\u0434\u044b\u0440\u0443",
  "card.member": "\u0418\u0435\u0441\u0456",
