  "card.back.title": "AEVION-\u0434\u0430 \u0442\u0435\u043a\u0441\u0435\u0440\u0443",
  "card.back.body1": "QR-\u0434\u044b \u0441\u043a\u0430\u043d\u0435\u0440\u043b\u0435\u0441\u0435\u04a3\u0456\u0437 \u2014 \u04d9\u043c\u0438\u044f\u043d\u043d\u044b\u04a3 \u0436\u0430\u0440\u0438\u044f \u043f\u0440\u043e\u0444\u0438\u043b\u0456 \u0430\u0448\u044b\u043b\u0430\u0434\u044b. \u0414\u0435\u04a3\u0433\u0435\u0439 \u043c\u0435\u043d Trust Score \u0431\u0430\u043d\u043a \u0456\u0448\u0456\u043d\u0434\u0435\u0433\u0456 \u0441\u043e\u043b \u0436\u0443\u0440\u043d\u0430\u043b\u0434\u0430\u043d \u0440\u0435\u043d\u0434\u0435\u0440 \u0435\u0442\u0456\u043b\u0435\u0434\u0456.",
  "card.back.body2": "\u041a\u0430\u0440\u0442\u0430 \u0442\u0430\u0441\u044b\u043c\u0430\u043b\u0434\u0430\u043d\u0431\u0430\u0439\u0434\u044b, \u043a\u0456\u043b\u0442\u0442\u0435\u0440 \u0441\u0430\u049b\u0442\u0430\u043b\u0493\u0430\u043d \u049b\u04b1\u0440\u044b\u043b\u0493\u044b\u0493\u0430 \u0431\u0430\u0439\u043b\u0430\u043d\u0493\u0430\u043d.",
