  "circlesPage.cta.body": "\u0425\u0430\u0431\u0430\u0440 \u0436\u0456\u0431\u0435\u0440\u0443, \u0442\u04e9\u043b\u0435\u043c\u0434\u0435\u0440 \u0436\u04d9\u043d\u0435 \u043c\u04af\u0448\u0435 \u049b\u043e\u0441\u0443 \u2014 \u04d9\u043c\u0438\u044f\u043d \u0456\u0448\u0456\u043d\u0434\u0435. \u0411\u04b1\u043b \u0431\u0435\u0442 \u0431\u0430\u0440\u043b\u044b\u049b \u0442\u043e\u043f\u0442\u0430\u0440\u0434\u044b \u0431\u0456\u0440 \u043a\u04e9\u0437\u049b\u0430\u0440\u0430\u0441\u043f\u0435\u043d \u0441\u043a\u0430\u043d\u0435\u0440\u043b\u0435\u0443 \u04af\u0448\u0456\u043d.",
