  "glossaryPage.lede": "\u0416\u0435\u0442\u0456 \u0442\u043e\u043f \u0431\u043e\u0439\u044b\u043d\u0448\u0430 {count} \u0442\u0435\u0440\u043c\u0438\u043d \u2014 \u0432\u0430\u043b\u044e\u0442\u0430, \u0441\u0435\u043d\u0456\u043c, \u0436\u0438\u043d\u0430\u049b, \u043a\u0440\u0435\u0434\u0438\u0442, \u049b\u04b1\u043f\u0438\u044f\u043b\u044b\u049b, \u04d9\u043b\u0435\u0443\u043c\u0435\u0442\u0442\u0456\u043a, \u044d\u043a\u043e\u0436\u04af\u0439\u0435. \u0406\u0437\u0434\u0435\u0443 \u043d\u0435\u043c\u0435\u0441\u0435 \u0442\u043e\u043f\u0442\u0430\u0440 \u0431\u043e\u0439\u044b\u043d\u0448\u0430 \u0430\u0439\u043d\u0430\u043b\u0434\u044b\u0440\u0443.",
