  // Flow /bank/flow
  "flowPage.kicker": "\u0410\u049b\u0448\u0430 \u0430\u0493\u044b\u043d\u044b",
  "flowPage.headline": "\u041a\u04e9\u0437\u0434\u0435\u0440 \u2192 \u04d9\u043c\u0438\u044f\u043d \u2192 \u0441\u0430\u043d\u0430\u0442\u0442\u0430\u0440.",
  "flowPage.lede": "Sankey \u0441\u0443\u0440\u0435\u0442\u0456: \u043a\u0456\u0440\u0456\u0441\u0442\u0435\u0440 \u0441\u043e\u043b \u0436\u0430\u049b\u0442\u0430, \u0448\u044b\u0493\u044b\u0441\u0442\u0430\u0440 \u043e\u04a3 \u0436\u0430\u049b\u0442\u0430. \u0410\u0440\u0430\u043b\u044b\u049b \u0442\u0430\u0441\u043f\u0430\u043b\u0430\u0440 \u04d9\u0440 \u043a\u04e9\u0437\u0434\u0456\u04a3 \u0430\u049b\u0448\u0430\u0441\u044b\u043d\u044b\u04a3 \u0441\u0430\u043d\u0430\u0442\u0442\u0430\u0440 \u0430\u0440\u0430\u0441\u044b\u043d\u0434\u0430 \u043f\u0440\u043e\u043f\u043e\u0440\u0446\u0438\u043e\u043d\u0430\u043b\u0434\u044b \u0431\u04e9\u043b\u0456\u043d\u0443\u0456\u043d \u043a\u04e9\u0440\u0441\u0435\u0442\u0435\u0434\u0456. Net \u0436\u043e\u0493\u0430\u0440\u044b\u0434\u0430.",
