  "tour.step.wallet.label": "\u04d8\u043c\u0438\u044f\u043d",
  "tour.step.wallet.headline": "AEC-\u04d9\u043c\u0438\u044f\u043d\u044b\u04a3\u044b\u0437 \u043e\u0441\u044b\u043d\u0434\u0430",
  "tour.step.wallet.body":
    "\u0422\u043e\u043b\u0442\u044b\u0440\u044b\u04a3\u044b\u0437, \u043a\u0435\u0437 \u043a\u0435\u043b\u0433\u0435\u043d \u0448\u043e\u0442\u049b\u0430 \u0436\u0456\u0431\u0435\u0440\u0456\u04a3\u0456\u0437 \u0436\u04d9\u043d\u0435 \u0431\u0430\u043b\u0430\u043d\u0441\u044b\u04a3\u044b\u0437\u0434\u044b\u04a3 \u0442\u0456\u0440\u0456 \u0433\u0440\u0430\u0444\u0438\u043a \u043f\u0435\u043d CoinTower \u0430\u043d\u0438\u043c\u0430\u0446\u0438\u044f\u0441\u044b\u043c\u0435\u043d \u04e9\u0441\u0456\u043f \u0436\u0430\u0442\u049b\u0430\u043d\u044b\u043d \u0431\u0430\u049b\u044b\u043b\u0430\u04a3\u044b\u0437. \u041a\u04e9\u0440\u0441\u0435\u0442\u0443 \u0432\u0430\u043b\u044e\u0442\u0430\u0441\u044b\u043d \u043a\u0435\u0437 \u043a\u0435\u043b\u0433\u0435\u043d \u0443\u0430\u049b\u044b\u0442\u0442\u0430 \u0430\u0443\u044b\u0441\u0442\u044b\u0440\u044b\u04a3\u044b\u0437 \u2014 \u043a\u043e\u043d\u0432\u0435\u0440\u0441\u0438\u044f \u0431\u0430\u0440\u043b\u044b\u049b \u0436\u0435\u0440\u0434\u0435 \u049b\u043e\u043b\u0434\u0430\u043d\u044b\u043b\u0430\u0434\u044b.",
  "tour.step.wallet.tip":
    "\u0410\u043b\u0434\u044b\u043c\u0435\u043d 500 AEC \u0442\u043e\u043b\u0442\u044b\u0440\u044b\u043f \u043a\u04e9\u0440\u0456\u04a3\u0456\u0437 \u2014 \u0431\u0430\u043b\u0430\u043d\u0441\u0442\u044b\u04a3 \u0430\u043d\u0438\u043c\u0430\u0446\u0438\u044f\u043b\u0430\u043d\u0493\u0430\u043d\u044b\u043d \u0436\u04d9\u043d\u0435 \u044d\u043a\u043e\u0436\u04af\u0439\u0435 \u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u043a\u0430\u0441\u044b\u043d\u044b\u04a3 \u0436\u0430\u04a3\u0430\u0440\u0493\u0430\u043d\u044b\u043d \u043a\u04e9\u0440\u0435\u0441\u0456\u0437.",
  "tour.step.ecosystem.label": "\u0411\u04af\u0433\u0456\u043d AEVION \u0431\u043e\u0439\u044b\u043d\u0448\u0430",
  "tour.step.ecosystem.headline": "\u0411\u0456\u0440 \u0442\u0430\u043c\u044b\u0440, \u0442\u04e9\u0440\u0442 \u043c\u043e\u0434\u0443\u043b\u044c",
  "tour.step.ecosystem.body":
    "\u04d8\u0440\u0431\u0456\u0440 QRight \u0442\u0435\u043a\u0441\u0435\u0440\u0443\u0456, CyberChess \u0442\u0443\u0440\u043d\u0438\u0440\u0456, Planet \u0431\u043e\u043d\u0443\u0441\u044b \u0436\u04d9\u043d\u0435 \u0431\u0430\u043d\u043a \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f\u0441\u044b \u043e\u0441\u044b \u0436\u043e\u043b\u0493\u0430 \u049b\u04b1\u0439\u044b\u043b\u0430\u0434\u044b. \u041a\u0435\u0437 \u043a\u0435\u043b\u0433\u0435\u043d \u043f\u043b\u0438\u0442\u043a\u0430\u0493\u0430 \u0431\u0430\u0441\u044b\u043f, \u0442\u0438\u0456\u0441\u0442\u0456 \u043c\u043e\u0434\u0443\u043b\u044c\u0433\u0435 \u04e9\u0442\u0456\u04a3\u0456\u0437 \u2014 \u0441\u0456\u0437\u0434\u0456\u04a3 \u0430\u049b\u0448\u0430 \u0442\u0430\u0440\u0438\u0445\u044b\u04a3\u044b\u0437 \u2014 \u044d\u043a\u043e\u0436\u04af\u0439\u0435\u043d\u0456\u04a3 \u0442\u0430\u0440\u0438\u0445\u044b.",
  "tour.step.forecast.label": "\u049a\u0430\u0440\u0436\u044b \u0431\u043e\u043b\u0436\u0430\u043c\u044b",
  "tour.step.forecast.headline": "\u0410\u049b\u0448\u0430\u04a3\u044b\u0437 \u049b\u0430\u0439\u0434\u0430 \u0431\u0430\u0493\u044b\u0442\u0442\u0430\u043b\u0493\u0430\u043d",
  "tour.step.forecast.body":
    "\u04ae\u0448 \u0441\u0446\u0435\u043d\u0430\u0440\u0438\u0439 \u00d7 \u04af\u0448 \u043a\u04e9\u043a\u0436\u0438\u0435\u043a, \u04d9\u0440 \u0436\u0438\u043d\u0430\u049b \u043c\u0430\u049b\u0441\u0430\u0442\u044b\u043d\u0430 \u043d\u0430\u049b\u0442\u044b \u043a\u04af\u043d-\u0431\u043e\u043b\u0436\u0430\u043c\u044b. \u0411\u043e\u043b\u0436\u0430\u043c \u0431\u0430\u0440\u043b\u044b\u049b \u043c\u043e\u0434\u0443\u043b\u044c\u0434\u0435\u0440 \u0431\u043e\u0439\u044b\u043d\u0448\u0430 30 \u043a\u04af\u043d\u0434\u0456\u043a \u0442\u0430\u0431\u044b\u0441 \u049b\u0430\u0440\u049b\u044b\u043d\u044b\u04a3\u044b\u0437\u0434\u044b \u0435\u0441\u0435\u043f\u043a\u0435 \u0430\u043b\u0430\u0434\u044b.",
  "tour.step.forecast.tip":
    "\u0421\u0446\u0435\u043d\u0430\u0440\u0438\u0439\u0434\u0456 \u00ab\u041e\u043f\u0442\u0438\u043c\u0438\u0441\u0442\u0456\u043a\u00bb \u0440\u0435\u0436\u0438\u043c\u0456\u043d\u0435 \u0430\u0443\u044b\u0441\u0442\u044b\u0440\u044b\u043f, 1 \u0436\u044b\u043b\u0434\u044b\u049b \u043a\u04af\u0440\u0434\u0435\u043b\u0456 \u04e9\u0441\u0443 \u043d\u04d9\u0442\u0438\u0436\u0435\u0441\u0456\u043d \u043a\u04e9\u0440\u0456\u04a3\u0456\u0437.",
  "tour.step.trust.label": "\u0421\u0435\u043d\u0456\u043c \u0436\u04d9\u043d\u0435 \u04d9\u0440\u0456\u043f\u0442\u0435\u0441\u0442\u0435\u0440",
  "tour.step.trust.headline": "AEVION \u0431\u043e\u0439\u044b\u043d\u0448\u0430 \u0431\u0435\u0434\u0435\u043b\u0456\u04a3\u0456\u0437",
  "tour.step.trust.body":
    "Ecosystem Trust Score \u0436\u0430\u043b\u0430\u049b\u044b \u0430\u0432\u0430\u043d\u0441 \u043b\u0438\u043c\u0438\u0442\u0442\u0435\u0440\u0456 \u043c\u0435\u043d \u04d9\u0440\u0456\u043f\u0442\u0435\u0441\u0442\u0435\u0440 \u0440\u0435\u0439\u0442\u0438\u043d\u0433\u0456\u043d\u0435 \u04d9\u0441\u0435\u0440 \u0435\u0442\u0435\u0434\u0456. \u00ab\u0415\u04a3 \u0436\u044b\u043b\u0434\u0430\u043c \u0436\u0435\u04a3\u0456\u0441\u0442\u0435\u0440\u00bb \u049b\u0430\u043d\u0434\u0430\u0439 \u04d9\u0440\u0435\u043a\u0435\u0442\u0442\u0435\u0440 \u0431\u0430\u043b\u044b\u04a3\u044b\u0437\u0434\u044b \u043a\u04af\u0448\u0442\u0456\u0440\u0435\u043a \u043a\u04e9\u0442\u0435\u0440\u0435\u0442\u0456\u043d\u0456\u043d \u043a\u04e9\u0440\u0441\u0435\u0442\u0435\u0434\u0456.",
  "tour.step.trust.tip":
    "\u0416\u0435\u0434\u0435\u043b \u0430\u0432\u0430\u043d\u0441 \u0430\u0448\u0443 \u04af\u0448\u0456\u043d Growing \u0434\u0435\u04a3\u0433\u0435\u0439\u0456\u043d\u0434\u0435\u0433\u0456 \u0431\u0430\u043b\u043b (20+) \u043a\u0435\u0440\u0435\u043a.",
  "tour.step.achievements.label": "\u0416\u0435\u0442\u0456\u0441\u0442\u0456\u043a\u0442\u0435\u0440",
  "tour.step.achievements.headline": "18 \u0431\u0435\u043b\u0433\u0456, 4 \u0431\u0430\u0493\u044b\u0442",
  "tour.step.achievements.body":
    "\u04d8\u0440\u0431\u0456\u0440 \u04d9\u0440\u0435\u043a\u0435\u0442\u0456\u04a3\u0456\u0437 Banking / Creator / Ecosystem / Security \u0431\u0430\u0493\u044b\u0442\u0442\u0430\u0440\u044b\u043d\u0434\u0430 \u0431\u0435\u043b\u0433\u0456\u043b\u0435\u0440\u0434\u0456 \u0430\u0448\u0430\u0434\u044b. \u0416\u0430\u0431\u044b\u049b \u0431\u0435\u043b\u0433\u0456\u043b\u0435\u0440 \u043c\u0430\u049b\u0441\u0430\u0442\u049b\u0430 \u049b\u0430\u043d\u0448\u0430\u043b\u044b\u049b\u0442\u044b \u0436\u0430\u049b\u044b\u043d \u0442\u04b1\u0440\u0493\u0430\u043d\u044b\u04a3\u044b\u0437\u0434\u044b \u043a\u04e9\u0440\u0441\u0435\u0442\u0435\u0434\u0456.",
  "tour.step.achievements.tip":
    "\u0411\u0438\u043e\u043c\u0435\u0442\u0440\u0438\u044f\u043d\u044b \u049b\u043e\u0441\u044b\u04a3\u044b\u0437, \u0431\u0456\u0440 \u0430\u0443\u0434\u0430\u0440\u043c\u0430\u043d\u044b \u049b\u043e\u043b \u049b\u043e\u0439\u044b\u04a3\u044b\u0437 \u0436\u04d9\u043d\u0435 QRight-\u0442\u0430 \u0436\u04b1\u043c\u044b\u0441\u0442\u044b \u0442\u0456\u0440\u043a\u0435\u04a3\u0456\u0437 \u2014 \u0430\u043b\u0493\u0430\u0448\u049b\u044b \u04af\u0448 \u0431\u0435\u043b\u0433\u0456 \u0431\u0456\u0440\u0434\u0435\u043d \u0441\u0456\u0437\u0434\u0456\u043a\u0456.",

