  "copilot.headline.empty": "\u0411\u0435\u043b\u0441\u0435\u043d\u0434\u0456 \u0435\u0441\u043a\u0435\u0440\u0442\u0443\u043b\u0435\u0440 \u0436\u043e\u049b \u2014 \u0431\u04d9\u0440\u0456 \u0442\u044b\u043d\u044b\u0448.",
  "copilot.empty.main": "\u0411\u0435\u043b\u0441\u0435\u043d\u0434\u0456 \u0435\u0441\u043a\u0435\u0440\u0442\u0443\u043b\u0435\u0440 \u0436\u043e\u049b \u2014 Copilot \u0444\u043e\u043d\u0434\u0430 \u0431\u0430\u049b\u044b\u043b\u0430\u0443\u0434\u0430.",
  "copilot.empty.hint": "\u0414\u0435\u0440\u0431\u0435\u0441 \u0441\u0438\u0433\u043d\u0430\u043b\u0434\u0430\u0440 \u04af\u0448\u0456\u043d \u043c\u0430\u049b\u0441\u0430\u0442, \u0442\u04b1\u0440\u0430\u049b\u0442\u044b \u0442\u04e9\u043b\u0435\u043c \u043d\u0435\u043c\u0435\u0441\u0435 \u0442\u043e\u043b\u044b\u049b\u0442\u044b\u0440\u0443 \u049b\u043e\u0441\u044b\u04a3\u044b\u0437.",
