  "copilot.footer.sortedBy": "\u0416\u0435\u0434\u0435\u043b\u0434\u0456\u043a \u0431\u043e\u0439\u044b\u043d\u0448\u0430 \u0441\u04b1\u0440\u044b\u043f\u0442\u0430\u043b\u0493\u0430\u043d \u00b7 \u0442\u0435\u043a \u0436\u0435\u0440\u0433\u0456\u043b\u0456\u043a\u0442\u0456 \u0441\u0438\u0433\u043d\u0430\u043b\u0434\u0430\u0440",
  "copilot.footer.dismissAll": "\u0411\u0430\u0440\u043b\u044b\u0493\u044b\u043d 24 \u0441\u0430\u0493\u0430\u0442\u049b\u0430 \u0436\u0430\u0441\u044b\u0440\u0443",
  "copilot.toast.cleared": "\u0415\u0441\u043a\u0435\u0440\u0442\u0443\u043b\u0435\u0440 24 \u0441\u0430\u0493\u0430\u0442\u049b\u0430 \u0436\u0430\u0441\u044b\u0440\u044b\u043b\u0434\u044b",
  "copilot.freeze.confirm": "\u04d8\u043c\u0438\u044f\u043d\u0434\u044b \u049b\u0430\u0442\u044b\u0440\u0443?\n\n\u0411\u0430\u0440\u043b\u044b\u049b \u0448\u044b\u0493\u044b\u0441 \u0430\u0443\u0434\u0430\u0440\u044b\u043c\u0434\u0430\u0440 5 \u043c\u0438\u043d\u0443\u0442\u049b\u0430 \u0431\u04e9\u0433\u0435\u043b\u0435\u0434\u0456. \u041a\u0435\u0439\u0456\u043d\u043d\u0435\u043d \u0431\u0438\u043e\u043c\u0435\u0442\u0440\u0438\u044f \u043d\u0435\u043c\u0435\u0441\u0435 \u0443\u0430\u049b\u044b\u0442 \u0431\u043e\u0439\u044b\u043d\u0448\u0430 \u0435\u0440\u0456\u0442\u0443 \u043c\u04af\u043c\u043a\u0456\u043d.",
  "copilot.freeze.toast.frozen": "\ud83d\udd12 \u04d8\u043c\u0438\u044f\u043d \u049b\u0430\u0442\u044b\u0440\u044b\u043b\u0434\u044b \u00b7 5 \u043c\u0438\u043d \u0441\u0430\u043b\u049b\u044b\u043d\u0434\u0430\u0443 \u0442\u0435\u0440\u0435\u0437\u0435\u0441\u0456 \u0431\u0430\u0441\u0442\u0430\u043b\u0434\u044b",
