  "copilot.ap.rule4.title": "\u0415\u0440\u0435\u0436\u0435 \u21164 \u00b7 \u0422\u0430\u0439\u043c\u043b\u043e\u043a \u0431\u0430\u043b\u0430\u043d\u0441 \u049b\u043e\u0440\u0493\u0430\u0443\u0448\u044b\u0441\u044b",
