  "copilot.ap.set.timelockGuard.hint": "\u0410\u043b\u0434\u0430\u0493\u044b {hours}\u0441 \u0456\u0448\u0456\u043d\u0434\u0435 \u0430\u0448\u044b\u043b\u0430\u0442\u044b\u043d \u0441\u044b\u0439\u043b\u044b\u049b\u0442\u0430\u0440 \u0441\u043e\u043c\u0430\u0441\u044b\u043d\u0430\u043d \u0442\u04e9\u043c\u0435\u043d \u0442\u04af\u0441\u0456\u0440\u0435\u0442\u0456\u043d \u0448\u044b\u0493\u044b\u0441\u0442\u044b \u0431\u04e9\u0433\u0435\u0443",
  "copilot.ap.set.timelockHr.label": "\u049a\u043e\u0440\u0493\u0430\u0443 \u0442\u0435\u0440\u0435\u0437\u0435\u0441\u0456",
  "copilot.ap.set.timelockHr.hint": "\u0420\u0435\u0437\u0435\u0440\u0432\u0442\u0456 \u0435\u0441\u0435\u043f\u0442\u0435\u0443 \u04af\u0448\u0456\u043d \u0431\u043e\u043b\u0436\u0430\u0443 \u043a\u04e9\u043a\u0436\u0438\u0435\u0433\u0456",
  "copilot.ap.summary": "\u0410\u0432\u0442\u043e\u043f\u0438\u043b\u043e\u0442 \u0434\u0435\u0442\u0435\u0440\u043c\u0438\u043d\u0438\u0440\u043b\u0435\u043d\u0433\u0435\u043d: 60\u0441 \u0442\u0438\u043a\u043a\u0435 \u0431\u0456\u0440 \u04d9\u0440\u0435\u043a\u0435\u0442, \u049b\u0430\u0443\u0456\u043f\u0441\u0456\u0437\u0434\u0456\u043a \u0431\u0443\u0444\u0435\u0440\u0456\u043d\u0435\u043d \u0435\u0448\u049b\u0430\u0448\u0430\u043d \u0442\u04e9\u043c\u0435\u043d\u0434\u0435\u043c\u0435\u0439\u0434\u0456, \u043a\u04af\u043d\u0434\u0456\u043a \u0448\u0435\u043a\u0442\u0435\u043d \u0430\u0441\u043f\u0430\u0439\u0434\u044b, \u0430\u0440\u0430\u043b\u044b\u049b-\u0448\u043e\u0442 \u0430\u0443\u0434\u0430\u0440\u044b\u043c\u0434\u0430\u0440\u044b\u043d\u0430 \u049b\u043e\u043b \u049b\u043e\u0439\u043c\u0430\u0439\u0434\u044b. \u0415\u0440\u0435\u0436\u0435 \u21162 (\u043a\u0456\u0440\u0456\u0441-\u0431\u04e9\u043b\u0443) \u0441\u04d9\u0439\u043a\u0435\u0441 \u043a\u0435\u043b\u0433\u0435\u043d\u0434\u0435 \u0431\u0456\u0440\u0456\u043d\u0448\u0456 \u0456\u0441\u043a\u0435 \u049b\u043e\u0441\u044b\u043b\u0430\u0434\u044b; \u0435\u0440\u0435\u0436\u0435 \u21161 (\u049b\u0443\u0443) \u2014 \u0440\u0435\u0437\u0435\u0440\u0432\u0442\u0456\u043a. \u0415\u0440\u0435\u0436\u0435 \u21163 (\u0430\u043d\u043e\u043c\u0430\u043b\u0438\u044f-\u043a\u04af\u0437\u0435\u0442\u0448\u0456) \u04d9\u0440 15\u0441 \u0442\u0435\u043a\u0441\u0435\u0440\u0435\u0434\u0456 \u0436\u04d9\u043d\u0435 \u049b\u043e\u0441\u044b\u043b\u0493\u0430\u043d\u0434\u0430 \u0441\u043e\u043b 5 \u043c\u0438\u043d \u0434\u0430\u0431\u044b\u043b\u0434\u044b \u049b\u0430\u0442\u044b\u0440\u0443\u0434\u044b \u0430\u0432\u0442\u043e \u0456\u0441\u043a\u0435 \u049b\u043e\u0441\u0430\u0434\u044b \u2014 \u043a\u0435\u0437\u0435\u043a\u0442\u0456 \u0430\u0432\u0442\u043e-\u049b\u0430\u0442\u044b\u0440\u0443\u043b\u0430\u0440 \u0430\u0440\u0430\u0441\u044b\u043d\u0434\u0430 10 \u043c\u0438\u043d \u043a\u04af\u0442\u0443. \u0415\u0440\u0435\u0436\u0435 \u21164 (\u0442\u0430\u0439\u043c\u043b\u043e\u043a \u049b\u043e\u0440\u0493\u0430\u0443\u0448\u044b) \u043a\u04af\u0442\u0456\u043b\u0433\u0435\u043d \u0441\u044b\u0439\u043b\u044b\u049b \u0430\u0432\u0442\u043e-\u0456\u0441\u043a\u0435 \u049b\u043e\u0441\u044b\u043b\u0443\u044b\u043d\u0430 \u049b\u0430\u0443\u0456\u043f \u0442\u04e9\u043d\u0434\u0456\u0440\u0435\u0442\u0456\u043d \u0448\u044b\u0493\u044b\u0441\u0442\u044b \u0431\u04e9\u0433\u0435\u0439\u0434\u0456. \u04d8\u0440 \u04d9\u0440\u0435\u043a\u0435\u0442 \u0442\u04e9\u043c\u0435\u043d\u0434\u0435\u0433\u0456 \u0430\u0443\u0434\u0438\u0442 \u0430\u0440\u043d\u0430\u0441\u044b\u043d\u0434\u0430 \u0442\u0456\u0440\u043a\u0435\u043b\u0435\u0434\u0456.",
  "copilot.ap.dryrun.label": "\u0421\u044b\u043d\u0430\u049b \u0440\u0435\u0436\u0438\u043c\u0456 \u00b7 \u0430\u0493\u044b\u043c\u0434\u0430\u0493\u044b \u043a\u04af\u0439\u0434\u0456 \u0435\u0448\u0442\u0435\u04a3\u0435 \u04e9\u0437\u0433\u0435\u0440\u0442\u043f\u0435\u0439 \u0431\u0430\u0493\u0430\u043b\u0430\u0443.",
