  // Metric tooltips
  "tip.balance": "\u04d8\u043c\u0438\u044f\u043d\u044b\u04a3\u044b\u0437\u0434\u0430\u0493\u044b \u049b\u0430\u0437\u0456\u0440\u0433\u0456 AEC. AEC \u2014 P2P \u0430\u0443\u0434\u0430\u0440\u044b\u043c\u0434\u0430\u0440, \u0440\u043e\u044f\u043b\u0442\u0438 \u0436\u04d9\u043d\u0435 \u0436\u04af\u043b\u0434\u0435\u043b\u0435\u0440 \u04af\u0448\u0456\u043d AEVION \u044d\u043a\u043e\u0436\u04af\u0439\u0435 \u0431\u0456\u0440\u043b\u0456\u0433\u0456.",
  "tip.netflow": "\u0421\u043e\u04a3\u0493\u044b 30 \u043a\u04af\u043d\u0434\u0435 \u043a\u0456\u0440\u0456\u0441 \u043c\u0438\u043d\u0443\u0441 \u0448\u044b\u0493\u044b\u0441 AEC \u0441\u043e\u043c\u0430\u0441\u044b. \u0416\u0430\u0441\u044b\u043b = \u0436\u04b1\u043c\u0441\u0430\u0443\u0434\u0430\u043d \u043a\u04e9\u043f \u0442\u0430\u043f\u0442\u044b\u04a3\u044b\u0437.",
  "tip.ops": "\u0421\u043e\u04a3\u0493\u044b 30 \u043a\u04af\u043d\u0434\u0435\u0433\u0456 \u04d9\u043c\u0438\u044f\u043d \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f\u043b\u0430\u0440\u044b\u043d\u044b\u04a3 \u0441\u0430\u043d\u044b (\u0442\u043e\u043b\u044b\u049b\u0442\u044b\u0440\u0443 + \u0430\u0443\u0434\u0430\u0440\u044b\u043c\u0434\u0430\u0440).",
  "tip.lastActivity": "\u0421\u043e\u04a3\u0493\u044b \u04d9\u043c\u0438\u044f\u043d \u043e\u049b\u0438\u0493\u0430\u0441\u044b\u043d\u0430\u043d \u0431\u0435\u0440\u0433\u0456 \u0443\u0430\u049b\u044b\u0442.",
  "tip.trustScore": "\u0416\u0438\u044b\u043d\u0442\u044b\u049b \u0431\u0435\u0434\u0435\u043b 0\u2013100. 8 \u0444\u0430\u043a\u0442\u043e\u0440\u0434\u044b \u0431\u0456\u0440\u0456\u043a\u0442\u0456\u0440\u0435\u0434\u0456: \u0431\u0430\u043d\u043a\u0438\u043d\u0433, \u0440\u043e\u044f\u043b\u0442\u0438, \u0448\u0430\u0445\u043c\u0430\u0442, Planet, \u0430\u0443\u0434\u0438\u0442 \u049b\u043e\u043b\u0442\u0430\u04a3\u0431\u0430\u043b\u0430\u0440\u044b, \u0431\u0438\u043e\u043c\u0435\u0442\u0440\u0438\u044f, \u0436\u0435\u0442\u0456\u0441\u0442\u0456\u043a\u0442\u0435\u0440, \u0436\u0435\u043b\u0456. \u0416\u043e\u0493\u0430\u0440\u044b \u04b1\u043f\u0430\u0439 \u2014 \u04af\u043b\u043a\u0435\u043d \u0430\u0432\u0430\u043d\u0441 \u043b\u0438\u043c\u0438\u0442\u0456 \u043c\u0435\u043d \u0430\u0440\u0442\u044b\u049b\u0448\u044b\u043b\u044b\u049b\u0442\u0430\u0440.",
  "tip.trustTier": "\u0414\u0438\u0441\u043a\u0440\u0435\u0442\u0442\u0456 \u0431\u0435\u0434\u0435\u043b \u0434\u0435\u04a3\u0433\u0435\u0439\u0456 \u2014 New / Growing / Trusted / Elite. \u04d8\u0440 \u0434\u04d9\u0440\u0435\u0436\u0435 AEVION-\u043d\u044b\u04a3 27 \u043c\u043e\u0434\u0443\u043b\u0456\u043d\u0434\u0435 \u0430\u0440\u0442\u044b\u049b\u0448\u044b\u043b\u044b\u049b\u0442\u0430\u0440 \u0430\u0448\u0430\u0434\u044b.",
  "tip.advanceLimit": "\u049a\u0430\u0437\u0456\u0440\u0433\u0456 Trust-\u0434\u04d9\u0440\u0435\u0436\u0435\u04a3\u0456\u0437\u0433\u0435 \u0441\u04af\u0439\u0435\u043d\u0456\u043f \u049b\u0430\u0437\u0456\u0440 \u0441\u04b1\u0440\u0430\u0439 \u0430\u043b\u0430\u0442\u044b\u043d \u0435\u04a3 \u043a\u04e9\u043f \u0430\u0432\u0430\u043d\u0441. \u041a\u0456\u0440\u0456\u0441 \u0440\u043e\u044f\u043b\u0442\u0438/\u0448\u0430\u0445\u043c\u0430\u0442/Planet-\u0442\u0435\u043d \u0430\u0432\u0442\u043e-\u04e9\u0442\u0435\u043b\u0435\u0434\u0456.",
  "tip.earningPace": "\u0421\u043e\u04a3\u0493\u044b 30 \u043a\u04af\u043d \u0431\u043e\u0439\u044b\u043d\u0448\u0430 \u044d\u043a\u043e\u0436\u04af\u0439\u0435\u043d\u0456\u04a3 \u0431\u0430\u0440\u043b\u044b\u049b \u043a\u04e9\u0437\u0434\u0435\u0440\u0456\u043d\u0435\u043d \u043e\u0440\u0442\u0430\u0448\u0430 \u043a\u04af\u043d\u0434\u0456\u043a AEC \u0430\u0493\u044b\u043d\u044b.",
  "tip.runRate": "30 \u043a\u04af\u043d\u0434\u0456\u043a \u049b\u0430\u0440\u049b\u044b\u043d\u044b\u04a3\u044b\u0437 12 \u0430\u0439 \u0441\u0430\u049b\u0442\u0430\u043b\u0441\u0430 \u2014 \u043e\u0441\u044b\u043d\u0448\u0430\u043c\u0430 \u0442\u0430\u0431\u0430\u0441\u044b\u0437. \u041a\u0435\u043f\u0456\u043b\u0434\u0456\u043a \u0435\u043c\u0435\u0441 \u2014 \u043d\u0430\u0440\u044b\u049b\u0442\u0430\u0440 \u04e9\u0437\u0433\u0435\u0440\u0435\u0434\u0456.",
  "tip.peerStanding": "AEVION-\u043d\u044b\u04a3 ~1500 \u0431\u0435\u043b\u0441\u0435\u043d\u0434\u0456 \u04d9\u043c\u0438\u044f\u043d\u044b \u0430\u0440\u0430\u0441\u044b\u043d\u0434\u0430 4 \u04e9\u043b\u0448\u0435\u043c \u0431\u043e\u0439\u044b\u043d\u0448\u0430 \u043e\u0440\u043d\u044b\u04a3\u044b\u0437. \u041a\u0430\u043b\u0438\u0431\u0440\u043b\u0435\u043d\u0433\u0435\u043d \u0442\u0430\u0440\u0430\u043b\u0443 \u043d\u0435\u0433\u0456\u0437\u0456\u043d\u0434\u0435; \u043d\u0430\u049b\u0442\u044b leaderboard /api/ecosystem/leaderboard-\u043f\u0435\u043d \u0448\u044b\u0493\u0430\u0434\u044b.",
  "tip.totalEarnings": "\u042d\u043a\u043e\u0436\u04af\u0439\u0435\u043d\u0456\u04a3 4 \u043a\u04e9\u0437\u0456 \u0431\u043e\u0439\u044b\u043d\u0448\u0430 \u0441\u043e\u043c\u0430: \u0431\u0430\u043d\u043a\u0442\u0456\u043a \u043a\u0456\u0440\u0456\u0441\u0442\u0435\u0440, QRight \u0440\u043e\u044f\u043b\u0442\u0438\u043b\u0435\u0440, CyberChess \u0436\u04af\u043b\u0434\u0435\u043b\u0435\u0440, Planet \u0431\u043e\u043d\u0443\u0441\u0442\u0430\u0440.",
  "tip.spending": "recurring \u0436\u04d9\u043d\u0435 \u043c\u0435\u043a\u0435\u043d\u0436\u0430\u0439 \u043a\u0456\u0442\u0430\u0431\u044b\u043d\u0430\u043d \u0441\u0430\u043d\u0430\u0442\u0442\u0430\u043b\u0493\u0430\u043d \u0448\u044b\u0493\u044b\u0441 AEC. \u0410\u0439\u043b\u044b\u049b \u0431\u044e\u0434\u0436\u0435\u0442\u0442\u0456 \u049b\u0430\u0440\u0430\u0443 \u04af\u0448\u0456\u043d \u043f\u0430\u0439\u0434\u0430\u043b\u044b.",
  "tip.autopilotMoved": "Autopilot \u04e9\u0437\u0456 \u049b\u0430\u043d\u0448\u0430 AEC \u0436\u0438\u043d\u0430\u049b \u043c\u0430\u049b\u0441\u0430\u0442\u0442\u0430\u0440\u044b\u04a3\u044b\u0437\u0493\u0430 \u0430\u0443\u0434\u0430\u0440\u0434\u044b \u2014 \u0440\u04b1\u049b\u0441\u0430\u0442\u043f\u0435\u043d, \u043b\u0438\u043c\u0438\u0442\u043f\u0435\u043d, \u0430\u0443\u0434\u0438\u0442\u043f\u0435\u043d.",

