  "moneyFlow.title": "\u0410\u049b\u0448\u0430 \u0430\u0493\u044b\u043d\u044b",
  "moneyFlow.subtitle": "\u04d8\u0440 \u0442\u0438\u044b\u043d \u049b\u0430\u0439\u0434\u0430\u043d \u043a\u0435\u043b\u0434\u0456 \u2014 \u049b\u0430\u0439\u0434\u0430 \u043a\u0435\u0442\u0442\u0456",
  "moneyFlow.tooltip":
    "Sankey-\u0434\u0438\u0430\u0433\u0440\u0430\u043c\u043c\u0430\u0441\u044b: \u043a\u0456\u0440\u0456\u0441 \u043a\u04e9\u0437\u0434\u0435\u0440\u0456 \u04d9\u043c\u0438\u044f\u043d\u0493\u0430 \u049b\u04b1\u0439\u044b\u043b\u0430\u0434\u044b \u0436\u04d9\u043d\u0435 \u0448\u044b\u0493\u044b\u0441 \u0441\u0430\u043d\u0430\u0442\u0442\u0430\u0440\u044b \u0431\u043e\u0439\u044b\u043d\u0448\u0430 \u0430\u0493\u0430\u0434\u044b. \u041b\u0435\u043d\u0442\u0430 \u0435\u043d\u0456 = \u0441\u043e\u043c\u0430. \u041a\u0435\u0437\u0435\u04a3\u0434\u0456 \u0436\u043e\u0493\u0430\u0440\u0493\u044b \u0442\u04af\u0439\u043c\u0435\u043b\u0435\u0440\u043c\u0435\u043d \u0430\u0443\u044b\u0441\u0442\u044b\u0440\u044b\u04a3\u044b\u0437.",
  "moneyFlow.in": "\u041a\u0456\u0440\u0456\u0441",
  "moneyFlow.out": "\u0428\u044b\u0493\u044b\u0441",
  "moneyFlow.net": "\u0422\u0430\u0437\u0430 \u0430\u0493\u044b\u043d",
