  "netWorth.tooltip":
    "\u0421\u0442\u0435\u043a-\u0434\u0438\u0430\u0433\u0440\u0430\u043c\u043c\u0430: net worth = \u0431\u0430\u043d\u043a \u0431\u0430\u043b\u0430\u043d\u0441\u044b (\u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f\u043b\u0430\u0440\u0434\u0430\u043d \u049b\u0430\u043b\u043f\u044b\u043d\u0430 \u043a\u0435\u043b\u0442\u0456\u0440\u0456\u043b\u0433\u0435\u043d) + \u0436\u0438\u043d\u0430\u049b\u0442\u0430\u043b\u0493\u0430\u043d \u044d\u043a\u043e\u0436\u04af\u0439\u0435 \u043a\u0456\u0440\u0456\u0441\u0456 (qright + chess + planet) + \u043c\u0430\u049b\u0441\u0430\u0442\u0442\u0430\u0440\u0434\u044b\u04a3 \u0441\u044b\u0437\u044b\u049b\u0442\u044b\u049b \u0431\u0430\u0493\u0430\u043b\u0430\u0443\u044b. \u041c\u0430\u0440\u043a\u0435\u0440 \u2014 \u0442\u0435\u0440\u0435\u0437\u0435\u0434\u0435\u0433\u0456 \u0442\u0430\u0440\u0438\u0445\u0438 \u0448\u044b\u04a3.",
  "netWorth.empty": "\u0413\u0440\u0430\u0444\u0438\u043a \u04af\u0448\u0456\u043d \u043a\u0435\u043c\u0456\u043d\u0434\u0435 2 \u043a\u04af\u043d \u0431\u0435\u043b\u0441\u0435\u043d\u0434\u0456\u043b\u0456\u043a \u049b\u0430\u0436\u0435\u0442 \u2014 \u043e\u043f\u0435\u0440\u0430\u0446\u0438\u044f\u043b\u0430\u0440\u0434\u044b \u0436\u0430\u043b\u0493\u0430\u0441\u0442\u044b\u0440\u044b\u04a3\u044b\u0437.",
