  "subScan.title": "\u0416\u0430\u0437\u044b\u043b\u044b\u043c \u0441\u043a\u0430\u043d\u0435\u0440\u0456",
  "subScan.subtitle": "\u0420\u0435\u0433\u0443\u043b\u044f\u0440\u043b\u044b \u0442\u04e9\u043b\u0435\u043c\u0434\u0435\u0440\u0434\u0456 \u0431\u0435\u043b\u0433\u0456\u043b\u0435\u0439\u0434\u0456: \u0435\u0441\u043a\u0456\u0440\u0433\u0435\u043d, \u049b\u044b\u043c\u0431\u0430\u0442, \u049b\u0430\u0439\u0442\u0430\u043b\u0430\u043d\u0430\u0442\u044b\u043d",
  "subScan.tooltip":
    "\u042d\u0432\u0440\u0438\u0441\u0442\u0438\u043a\u0430\u043b\u044b\u049b \u0441\u043a\u0430\u043d\u0435\u0440\u043b\u0435\u0443. \u0415\u0441\u043a\u0456\u0440\u0433\u0435\u043d = \u226560 \u043a\u04af\u043d \u0456\u0441\u043a\u0435 \u049b\u043e\u0441\u044b\u043b\u043c\u0430\u0493\u0430\u043d. \u049a\u044b\u043c\u0431\u0430\u0442 = \u0430\u0439\u043b\u044b\u049b \u044d\u043a\u0432\u0438\u0432\u0430\u043b\u0435\u043d\u0442 \u0431\u0435\u043b\u0441\u0435\u043d\u0434\u0456 \u0436\u0430\u0437\u044b\u043b\u044b\u043c\u0434\u0430\u0440\u0434\u044b\u04a3 \u043c\u0435\u0434\u0438\u0430\u043d\u0430\u0441\u044b\u043d\u0430\u043d \u22652\u00d7 \u0430\u0441\u0430\u0434\u044b. \u049a\u0430\u0439\u0442\u0430\u043b\u0430\u043d\u0430\u0442\u044b\u043d = \u0430\u043b\u0443\u0448\u044b + \u043a\u0435\u0437\u0435\u04a3 + \u0441\u043e\u043c\u0430 \u0441\u04d9\u0439\u043a\u0435\u0441 \u043a\u0435\u043b\u0435\u0434\u0456. \u041a\u0456\u0434\u0456\u0440\u0442\u0443 / \u0416\u043e\u044e \u2014 \u0431\u0456\u0440\u0434\u0435\u043d.",
