  "challenge.tooltip":
    "\u0427\u0435\u043b\u043b\u0435\u043d\u0434\u0436\u0442\u0435\u0440 \u0442\u0435\u043a \u0442\u0456\u043a\u0435\u043b\u0435\u0439 \u0434\u0435\u0440\u0435\u043a\u0442\u0435\u0440\u0456\u04a3\u0456\u0437\u0434\u0435\u043d \u0435\u0441\u0435\u043f\u0442\u0435\u043b\u0435\u0434\u0456. \u04d8\u0440 \u0442\u0435\u0440\u0435\u0437\u0435\u043d\u0456\u04a3 \u0431\u0430\u0441\u044b\u043d\u0434\u0430 (\u043a\u04af\u043d / \u0430\u043f\u0442\u0430 / \u0430\u0439) \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0442\u044b \u0456\u0441\u043a\u0435 \u049b\u043e\u0441\u044b\u043b\u0430\u0434\u044b, \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0442\u0456 \u043d\u0430\u049b\u0442\u044b \u0443\u0430\u049b\u044b\u0442\u0442\u0430 \u0436\u0430\u04a3\u0430\u0440\u0442\u0430\u0434\u044b \u0436\u04d9\u043d\u0435 \u0442\u0435\u0440\u0435\u0437\u0435 \u0436\u0430\u0431\u044b\u043b\u0493\u0430\u043d\u0434\u0430 \u0436\u0435\u04a3\u0456\u0441/\u04b1\u0442\u044b\u043b\u044b\u0441 \u043a\u04af\u0439\u0456\u043d\u0435 \u0442\u0456\u0440\u043a\u0435\u043b\u0435\u0434\u0456. \u0421\u044b\u0439\u0430\u049b\u044b \u2014 \u0436\u0435\u04a3\u0456\u0441\u043a\u0435 \u0436\u0435\u0442\u043a\u0435\u043d \u0436\u0430\u0493\u0434\u0430\u0439\u0434\u0430\u0493\u044b AEC.",
