  "vault.tooltip":
    "\u0422\u0430\u0437\u0430 \u0438\u043c\u0438\u0442\u0430\u0446\u0438\u044f. AEC-\u0442\u0456 30 / 90 / 180 \u043a\u04af\u043d\u0433\u0435 3% / 5% / 8% APY-\u043c\u0435\u043d \u049b\u04b1\u043b\u044b\u043f\u0442\u0430\u04a3\u044b\u0437; \u043a\u0456\u0440\u0456\u0441 \u04af\u0437\u0434\u0456\u043a\u0441\u0456\u0437 \u0435\u0441\u0435\u043f\u0442\u0435\u043b\u0435\u0434\u0456 \u0436\u04d9\u043d\u0435 \u043c\u0435\u0440\u0437\u0456\u043c \u0430\u044f\u049b\u0442\u0430\u043b\u0493\u0430\u043d\u0434\u0430 (\u043d\u0435\u043c\u0435\u0441\u0435 \u0435\u0440\u0442\u0435\u0440\u0435\u043a 50% \u0430\u0439\u044b\u043f\u043f\u04b1\u043b\u043c\u0435\u043d) \u0430\u043b\u0443\u0493\u0430 \u0431\u043e\u043b\u0430\u0434\u044b. \u041f\u0440\u0438\u043d\u0446\u0438\u043f\u0430\u043b \u2014 \u0448\u0430\u0440\u0442\u0442\u044b; \u04d9\u043c\u0438\u044f\u043d \u0431\u0430\u043b\u0430\u043d\u0441\u044b \u0435\u0441\u0435\u043f\u0442\u0435\u043d \u0448\u044b\u049b\u043f\u0430\u0439\u0434\u044b.",
