Object.assign(translations.en, BANK_EXTRA_EN);
Object.assign(translations.ru, BANK_EXTRA_RU);
Object.assign(translations.kk, BANK_EXTRA_KK);

function interpolate(s: string, vars?: Record<string, string | number>): string {
  if (!vars) return s;
  let r = s;
  for (const [k, v] of Object.entries(vars)) {
    r = r.split(`{${k}}`).join(String(v));
  }
  return r;
}

export function useI18n() {
  const ctx = useContext(I18nContext);
  if (!ctx) throw new Error("useI18n must be used within I18nProvider");
  return ctx;
}

function isLang(x: unknown): x is Lang {
  return x === "en" || x === "ru" || x === "kk";
}

function detectBrowserLang(): Lang {
  if (typeof navigator === "undefined") return "en";
  const raw = (navigator.language || "en").toLowerCase();
  if (raw.startsWith("kk") || raw.startsWith("kz")) return "kk";
  if (raw.startsWith("ru")) return "ru";
  return "en";
}

export function I18nProvider({ children }: { children: React.ReactNode }) {
  const [lang, setLangState] = useState<Lang>("en");

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (isLang(saved)) {
        setLangState(saved);
        return;
      }
    } catch {}
    setLangState(detectBrowserLang());
  }, []);

  const setLang = useCallback((l: Lang) => {
    setLangState(l);
    try { localStorage.setItem(STORAGE_KEY, l); } catch {}
    if (typeof document !== "undefined") {
      document.documentElement.lang = l;
    }
  }, []);

  useEffect(() => {
    if (typeof document !== "undefined") {
      document.documentElement.lang = lang;
    }
  }, [lang]);

  const t = useCallback(
    (key: string, vars?: Record<string, string | number>): string => {
      const raw = translations[lang][key] || translations.en[key] || key;
      return interpolate(raw, vars);
    },
    [lang],
  );

  const value = useMemo(() => ({ lang, setLang, t }), [lang, setLang, t]);

  return <I18nContext.Provider value={value}>{children}</I18nContext.Provider>;
}

/** Compact language switcher component (EN / RU / KZ) */
export function LangSwitch() {
  const { lang, setLang } = useI18n();
  return (
    <div
      role="group"
      aria-label="Language"
      style={{
        display: "inline-flex",
        borderRadius: 8,
        border: "1px solid rgba(15,23,42,0.12)",
        overflow: "hidden",
        fontSize: 12,
      }}
    >
      {LANGS.map((l, i) => {
        const active = lang === l;
        return (
          <button
            key={l}
            type="button"
            onClick={() => setLang(l)}
            aria-pressed={active}
            title={LANG_FULL[l]}
            style={{
              padding: "5px 10px",
              border: "none",
              borderLeft: i === 0 ? "none" : "1px solid rgba(15,23,42,0.12)",
              background: active ? "#0f172a" : "transparent",
              color: active ? "#fff" : "#64748b",
              fontWeight: active ? 800 : 500,
              cursor: "pointer",
            }}
          >
            {LANG_SHORT[l]}
          </button>
        );
      })}
    </div>
  );
}
